// Map user experience level (1-5 slider) to maximum complexity acceptable.
// Level 1 = total beginner (avoid complexity-3 hard). Level 5 = advanced (all welcome).
// Levels 2-3 = intermediate (complexity 1-2 fine, 3 with caution). Level 4-5 = comfortable with all.
const EXPERIENCE_MAX_COMPLEXITY = { 1: 2, 2: 2, 3: 3, 4: 3, 5: 3 };
const EXPERIENCE_BONUS = {
  // Bonus added to exercise score based on experience-complexity match.
  // Beginners (1-2) get strong penalty for complexity-3 (effectively excluded).
  // Intermediates (3) tolerate but don't prefer complexity-3.
  // Advanced (4-5) get a positive nudge for complexity-3 (programming variety).
  1: { 1: 0, 2: -3, 3: -100 },
  2: { 1: 0, 2: -1, 3: -100 },
  3: { 1: 0, 2: 0,  3: -2 },
  4: { 1: 0, 2: 0,  3: 1 },
  5: { 1: 0, 2: 0,  3: 2 },
};

// Determine if profile is "short" / "tall" / "average" based on height (cm).
// Cutoffs differ by sex since population means differ.
function getHeightCategory(profile) {
  const h = profile.height || 0;
  const isMale = profile.sex === "M";
  // Cutoffs roughly match population quartiles
  if (isMale) {
    if (h < 170) return "short";
    if (h > 185) return "tall";
    return "average";
  } else {
    if (h < 158) return "short";
    if (h > 173) return "tall";
    return "average";
  }
}

// ============================================================
// WEIGHT INCREMENTS — per exercise, with sensible defaults by equipment
// ============================================================
// Default jump size for each equipment type (small lifts use smaller jumps).
const DEFAULT_INCREMENT_BY_EQUIPMENT = {
  "Barbell": 2.5,
  "Dumbbells": 1, // pairs go up by 1kg per dumbbell typically (so 2kg added total) — but per-DB display
  "Machine": 5,   // pin-loaded plate stacks usually 5kg
  "Cable": 5,     // cable stacks too
  "Bodyweight": 0,
};

// Resolve the increment for an exercise, honouring user override stored at u:{id}:increments
function getIncrement(exerciseName, userIncrements = {}) {
  if (userIncrements[exerciseName] !== undefined) return userIncrements[exerciseName];
  const eq = EXERCISE_LIBRARY[exerciseName]?.equipment;
  return DEFAULT_INCREMENT_BY_EQUIPMENT[eq] ?? 2.5;
}

// Snap a target weight to the nearest valid increment, given a current weight + increment
// e.g. current 25kg, incr 5kg, target 27.5 → 30kg (round up to next valid)
function snapToIncrement(currentWeight, targetWeight, increment) {
  if (increment <= 0) return targetWeight; // bodyweight or unset
  const delta = targetWeight - currentWeight;
  // Round delta to nearest increment
  const steps = Math.round(delta / increment);
  return Math.max(0, currentWeight + steps * increment);
}

