// ============================================================
// PROGRESSION ENGINE — per-session adjustments
// ============================================================
// Returns an array of per-exercise suggestions based on recent performance.
// Each suggestion: { exerciseName, type, current, suggested, reason, severity, evidence }
// Types: increase_weight | increase_reps | decrease_weight | reduce_sets | add_set | hold

function analyseProgress(lifts, profile, currentPlan, userIncrements = {}) {
  const out = [];
  const experience = profile.experience || "Intermediate";

  // Build a flat lookup of current prescribed sets per exercise from the plan
  const prescribedSets = {};
  const prescribedReps = {};
  if (currentPlan) {
    for (const session of currentPlan) {
      for (const ex of session.exercises) {
        prescribedSets[ex.name] = ex.sets;
        prescribedReps[ex.name] = ex.reps;
      }
    }
  }

  for (const [name, data] of Object.entries(lifts || {})) {
    const sessions = data?.history || [];
    if (sessions.length < 2) continue;

    const last = sessions[sessions.length - 1];
    const prev = sessions[sessions.length - 2];
    const prescribedSetCount = prescribedSets[name] || last.sets.length;
    const prescribedRepRange = prescribedReps[name] || "8-10";
    const range = parseRepRange(prescribedRepRange);

    // === Weight increase trigger ===
    // All sets at top of rep range AND avg RIR >= 1 → bump weight by exercise's increment
    const lastSetsAtTop = last.sets.every(s => s.reps >= range.top);
    const lastAvgRir = last.sets.reduce((sum, s) => sum + (s.rir ?? 0), 0) / last.sets.length;
    if (lastSetsAtTop && lastAvgRir >= 1 && last.sets[0].weight > 0) {
      const currentWt = last.sets[0].weight;
      const incr = getIncrement(name, userIncrements);
      if (incr > 0) {
        out.push({
          exerciseName: name,
          type: "increase_weight",
          current: currentWt,
          suggested: currentWt + incr,
          reason: `Hit top of range (${range.top} reps) on every set with ${lastAvgRir.toFixed(1)} reps in tank — add ${incr}kg.`,
          severity: "med",
          evidence: { reps: last.sets.map(s => s.reps), avgRir: lastAvgRir },
        });
        continue;
      }
    }

    // === Rep increase trigger ===
    const allWithinRange = last.sets.every(s => s.reps >= range.bottom);
    if (allWithinRange && lastAvgRir >= 2 && !lastSetsAtTop) {
      out.push({
        exerciseName: name,
        type: "increase_reps",
        current: Math.max(...last.sets.map(s => s.reps)),
        suggested: Math.min(range.top, Math.max(...last.sets.map(s => s.reps)) + 1),
        reason: `Reps in range with ${lastAvgRir.toFixed(1)} RIR on average — squeeze 1 more rep next session before adding weight.`,
        severity: "low",
        evidence: { reps: last.sets.map(s => s.reps), avgRir: lastAvgRir },
      });
      continue;
    }

    // === Weight decrease trigger ===
    const both = [last, prev];
    const tooHeavy = both.every(s => s.sets[0]?.reps < range.bottom && (s.sets[0]?.rir ?? 2) === 0);
    if (tooHeavy && last.sets[0].weight > 0) {
      const currentWt = last.sets[0].weight;
      const decr = getIncrement(name, userIncrements);
      if (decr > 0) {
        out.push({
          exerciseName: name,
          type: "decrease_weight",
          current: currentWt,
          suggested: Math.max(0, currentWt - decr),
          reason: `Couldn't hit ${range.bottom} reps with low RIR for 2 sessions. Drop ${decr}kg to find your sweet spot.`,
          severity: "high",
          evidence: { setOneReps: [prev.sets[0]?.reps, last.sets[0]?.reps] },
        });
        continue;
      }
    }

    // === Set reduction trigger (fatigue + over-prescribed) ===
    // Last set across recent sessions consistently RIR 0 AND below target reps → drop a set
    if (prescribedSetCount > 2) {
      const recentSessions = sessions.slice(-3);
      const lateFails = recentSessions.filter(s => {
        const ls = s.sets[s.sets.length - 1];
        return ls && (ls.rir ?? 2) === 0 && ls.reps < range.bottom;
      }).length;
      if (lateFails >= 2) {
        out.push({
          exerciseName: name,
          type: "reduce_sets",
          current: prescribedSetCount,
          suggested: prescribedSetCount - 1,
          reason: `Last set hit failure with reps below target across ${lateFails}/${recentSessions.length} sessions. Drop a set, push the remaining ones harder.`,
          severity: "med",
          evidence: { lateFails, total: recentSessions.length },
        });
        continue;
      }
    }

    // === Set addition trigger (under-stimulus) ===
    // All sets in range with RIR 3+ across last 2 sessions, and prescribed sets < 4 → add a set
    if (prescribedSetCount < 4 && experience !== "Beginner") {
      const cushy = both.every(s => {
        const allInRange = s.sets.every(set => set.reps >= range.bottom);
        const veryEasy = s.sets.every(set => (set.rir ?? 0) >= 3);
        return allInRange && veryEasy;
      });
      if (cushy) {
        out.push({
          exerciseName: name,
          type: "add_set",
          current: prescribedSetCount,
          suggested: prescribedSetCount + 1,
          reason: `All sets clearly in tank (3+ RIR) across 2 sessions — your stimulus is too light. Add a set.`,
          severity: "low",
          evidence: { sessions: 2 },
        });
        continue;
      }
    }
  }

  return out;
}

// Monthly check-in: structural recommendations
// Triggers: every 4 weeks since last check-in OR end of training block
function generateMonthlyCheckin(lifts, blocks, completions, profile) {
  const out = [];
  const today = new Date();
  const fourWeeksAgo = new Date(today); fourWeeksAgo.setDate(fourWeeksAgo.getDate() - 28);
  const cutoff = fourWeeksAgo.toISOString().split("T")[0];

  // 1. Stalled exercises — no e1RM growth in 4 weeks → suggest swap
  for (const [name, data] of Object.entries(lifts || {})) {
    const sessions = data?.history || [];
    const recent = sessions.filter(s => s.date >= cutoff);
    if (recent.length < 3) continue;
    const e1RMs = recent.map(s => s.sets.reduce((m, set) => Math.max(m, set.weight && set.reps ? set.weight * (36 / Math.max(1, 37 - set.reps)) : 0), 0));
    const first = e1RMs[0], last = e1RMs[e1RMs.length - 1];
    if (first > 0) {
      const growthPct = ((last - first) / first) * 100;
      if (growthPct < 1.5) {
        out.push({
          type: "swap_exercise",
          exerciseName: name,
          reason: `Only ${growthPct.toFixed(1)}% e1RM growth over 4 weeks. Time to rotate this lift for a fresh stimulus.`,
          severity: "med",
        });
      }
    }
  }

  // 2. Volume distribution — low or excess weekly sets per muscle
  const cutoff7 = new Date(today); cutoff7.setDate(cutoff7.getDate() - 7);
  const cutoff7Str = cutoff7.toISOString().split("T")[0];
  const weeklyByMuscle = {};
  for (const [name, data] of Object.entries(lifts || {})) {
    const muscle = MUSCLE_GROUPS_FOR_FATIGUE[name];
    if (!muscle) continue;
    const sets = (data?.history || []).filter(s => s.date >= cutoff7Str).reduce((s, ses) => s + ses.sets.length, 0);
    weeklyByMuscle[muscle] = (weeklyByMuscle[muscle] || 0) + sets;
  }
  const volumeIdeals = { Chest: [10, 18], Back: [10, 20], Legs: [10, 18], Hamstrings: [6, 12], Shoulders: [8, 16], Biceps: [8, 14], Triceps: [8, 14], Core: [6, 16], Calves: [8, 16] };
  for (const [muscle, sets] of Object.entries(weeklyByMuscle)) {
    const ideal = volumeIdeals[muscle];
    if (!ideal || sets === 0) continue;
    if (sets < ideal[0]) {
      out.push({
        type: "increase_volume",
        muscle,
        reason: `${muscle}: ${sets} sets/week, ideal is ${ideal[0]}-${ideal[1]}. Adding sets to existing exercises will speed gains.`,
        severity: "med",
      });
    } else if (sets > ideal[1] + 4) {
      out.push({
        type: "decrease_volume",
        muscle,
        reason: `${muscle}: ${sets} sets/week, well over the ${ideal[1]} ideal cap. Cutting back protects recovery.`,
        severity: "low",
      });
    }
  }

  // 3. Adherence check — workouts/week vs target
  let workoutDays = 0;
  for (let i = 0; i < 28; i++) {
    const d = new Date(today); d.setDate(d.getDate() - i);
    const ds = d.toISOString().split("T")[0];
    if (completions[ds]?.length > 0) workoutDays++;
  }
  const expected = (profile.daysPerWeek || 4) * 4;
  const adherence = expected > 0 ? workoutDays / expected : 0;
  if (adherence < 0.6) {
    out.push({
      type: "schedule_review",
      reason: `Only ${workoutDays} of ${expected} planned workouts hit in 4 weeks. Consider dropping to ${Math.max(1, profile.daysPerWeek - 1)} days/week — consistency beats ambition.`,
      severity: "med",
    });
  }

  return out;
}

