// ============================================================
// INTENSIFICATION — engine-suggested supersets and dropsets
// ============================================================

// Antagonist muscle pairs. When two adjacent exercises hit antagonist muscles,
// they're prime superset candidates (no fatigue spillover, time-efficient).
const ANTAGONIST_PAIRS = {
  "Chest": ["Back"],
  "Back": ["Chest"],
  "Biceps": ["Triceps"],
  "Triceps": ["Biceps"],
  "Quads": ["Hamstrings", "Glutes"],
  "Legs": ["Hamstrings", "Glutes"],
  "Hamstrings": ["Quads", "Legs"],
  "Glutes": ["Quads", "Legs"],
};

// Compound lifts that should NEVER get auto-supersetted or dropsetted.
// Keep heavy compounds as straight sets — load progression matters most here,
// and intensification fatigues form first.
const NEVER_INTENSIFY = new Set([
  "Barbell Squat", "Barbell Bench Press", "Barbell Row",
  "Romanian Deadlift", "Overhead Press", "Pull-ups",
]);

// Isolation / single-joint exercises that DO benefit from dropsets
// (smaller muscles recover fast, can handle the extra stimulus).
const DROPSET_FRIENDLY = new Set([
  "Lateral Raise", "Cable Lateral Raise",
  "Barbell Curl", "Dumbbell Curl", "Cable Curl", "Hammer Curl",
  "Tricep Pushdown", "Skull Crushers", "Overhead Tricep Extension",
  "Hamstring Curl", "Leg Extension",
  "Standing Calf Raise", "Cable Fly", "Face Pull",
  "Glute Bridge", "Hip Thrust", "Cable Pull-Through", "Cable Crunch",
]);

// Apply engine intensification suggestions to an array of session exercises.
// Mutates and returns the array — adds `supersetWith` / `supersetRole` and
// `dropsetSuggested: { lastSet: true, reason: "..." }` where appropriate.
//
// Rules:
// - Skip if user has globally disabled this intensification type
// - Skip if user has dismissed this specific exercise+date (per-session opt-out)
// - Skip exercises in NEVER_INTENSIFY (heavy compounds stay straight)
// - Skip experience level 1-2 (beginners build form first; level 3+ gets suggestions)
// - Variety: cap supersets at 1 pair per session, dropsets at 1-2 per session
// - Spread types: prefer sessions to mix straight + superset + dropset, not double up
function applyIntensifications(exercises, profile, preferences, dateStr) {
  const intensificationEnabled = preferences.intensificationEnabled || { supersets: true, dropsets: true };
  const skips = preferences.skipIntensification || {};
  const userSupersets = preferences.supersets || {}; // user-pinned pairs override engine
  const experience = profile.experience || 3;

  // Experience gate: beginners (1-2) get no intensifications — straight sets only.
  // Level 3 gets dropsets cautiously. Level 4-5 gets full variety.
  const allowSupersets = intensificationEnabled.supersets && experience >= 3;
  const allowDropsets = intensificationEnabled.dropsets && experience >= 3;

  let supersetCount = 0;
  let dropsetCount = 0;
  const supersetCap = experience >= 4 ? 2 : 1; // advanced lifters can handle 2 superset pairs per session
  const dropsetCap = experience >= 4 ? 2 : 1;

  // CROSS-WEEK ROTATION: build a recency map of exercises that received intensification
  // recently. Newer = stronger penalty. Used to bias the engine away from giving the
  // same exercises supersets/dropsets every single week.
  // History entries: { date: "YYYY-MM-DD", type: "superset"|"dropset", names: [...] }
  const history = preferences.intensificationHistory || [];
  const today = new Date(dateStr);
  const supersetRecency = {};
  const dropsetRecency = {};
  for (const entry of history) {
    const daysAgo = Math.floor((today - new Date(entry.date)) / (1000 * 60 * 60 * 24));
    if (daysAgo < 0 || daysAgo > 21) continue; // 3-week window
    const decay = Math.max(0, 1 - daysAgo / 21); // 1.0 today, 0.0 at 21+ days
    const map = entry.type === "superset" ? supersetRecency : dropsetRecency;
    for (const name of entry.names || []) {
      map[name] = (map[name] || 0) + decay;
    }
  }
  // Skip threshold: if combined recency for a candidate >= 0.5, skip (give another exercise a turn)
  const recencyThreshold = 0.5;

  // Pass 1: honour user-pinned supersets first
  for (const [aName, bName] of Object.entries(userSupersets)) {
    const a = exercises.find(e => e.name === aName);
    const b = exercises.find(e => e.name === bName);
    if (a && b) {
      a.supersetWith = bName; a.supersetRole = "A"; a.supersetSource = "user";
      b.supersetWith = aName; b.supersetRole = "B"; b.supersetSource = "user";
      supersetCount++;
    }
  }

  // Pass 2: auto-suggest supersets for antagonist adjacent pairs.
  // Iterate twice: first pass skips pairs with high recency; if no pair fired,
  // do a second pass without the recency filter so a session never goes entirely flat.
  if (allowSupersets) {
    for (const ignoreRecency of [false, true]) {
      if (supersetCount >= supersetCap) break;
      for (let i = 0; i < exercises.length - 1; i++) {
        if (supersetCount >= supersetCap) break;
        const a = exercises[i];
        const b = exercises[i + 1];
        // Skip if either is already paired or in never-list
        if (a.supersetWith || b.supersetWith) continue;
        if (NEVER_INTENSIFY.has(a.name) || NEVER_INTENSIFY.has(b.name)) continue;
        // Skip if user dismissed this pair today
        const skipKey = `superset:${a.name}+${b.name}:${dateStr}`;
        if (skips[skipKey]) continue;
        const aMuscle = MUSCLE_GROUPS_FOR_FATIGUE[a.name];
        const bMuscle = MUSCLE_GROUPS_FOR_FATIGUE[b.name];
        const antagonists = ANTAGONIST_PAIRS[aMuscle] || [];
        if (!antagonists.includes(bMuscle)) continue;
        // Both should be similar position in session (not first heavy compound)
        if (i === 0) continue; // never superset the opening compound
        // Cross-week rotation: skip if this exact pair was supersetted recently
        if (!ignoreRecency) {
          const recency = (supersetRecency[a.name] || 0) + (supersetRecency[b.name] || 0);
          if (recency >= recencyThreshold) continue;
        }
        a.supersetWith = b.name; a.supersetRole = "A"; a.supersetSource = "engine";
        a.supersetReason = `${aMuscle}/${bMuscle} pair — no fatigue spillover, saves time`;
        b.supersetWith = a.name; b.supersetRole = "B"; b.supersetSource = "engine";
        b.supersetReason = a.supersetReason;
        supersetCount++;
      }
    }
  }

  // Pass 3: auto-suggest dropsets on isolation exercises late in the session.
  // Same two-pass approach with recency fallback.
  if (allowDropsets) {
    for (const ignoreRecency of [false, true]) {
      if (dropsetCount >= dropsetCap) break;
      for (let i = Math.floor(exercises.length / 2); i < exercises.length; i++) {
        if (dropsetCount >= dropsetCap) break;
        const ex = exercises[i];
        if (ex.dropsetSuggested) continue; // already done
        if (NEVER_INTENSIFY.has(ex.name)) continue;
        if (!DROPSET_FRIENDLY.has(ex.name)) continue;
        if (ex.supersetWith) continue; // don't stack superset + dropset
        const skipKey = `dropset:${ex.name}:${dateStr}`;
        if (skips[skipKey]) continue;
        // Recency: skip if this exercise got a dropset recently
        if (!ignoreRecency) {
          const recency = dropsetRecency[ex.name] || 0;
          if (recency >= recencyThreshold) continue;
        }
        ex.dropsetSuggested = {
          lastSet: true,
          reason: `${MUSCLE_GROUPS_FOR_FATIGUE[ex.name] || "Muscle"} responds well to extra stimulus on the last set`,
          source: "engine",
        };
        dropsetCount++;
      }
    }
  }

  return exercises;
}

// ============================================================
// PROGRESSION SCORING — for end-of-block rotation
// ============================================================

// Calculate weekly volume growth from a lift's history. Returns null if insufficient data.
// Uses simple linear-fit slope on recent sessions, normalised to % change per session.
function calculateGrowthScore(history) {
  if (!history || history.length < 3) return null;
  const recent = history.slice(-6); // last 6 sessions
  const volumes = recent.map(h => h.sets.reduce((s, set) => s + set.weight * set.reps, 0));
  const firstVol = volumes[0];
  if (firstVol === 0) return null;
  const lastVol = volumes[volumes.length - 1];
  // Pct change per session
  const totalGrowthPct = ((lastVol - firstVol) / firstVol) * 100;
  const perSession = totalGrowthPct / (volumes.length - 1);
  // Score: 0 if flat or negative, scales up to 100 at +3% per session (very fast growth)
  const score = Math.max(0, Math.min(100, perSession * 33.3));
  return { score, perSessionPct: perSession, sessions: volumes.length };
}

// Combined keep/drop score per exercise: weighted growth + enjoyment
// Returns 0-100 where lower = drop candidate
function calculateExerciseScore(exName, lifts, ratings) {
  const history = lifts[exName]?.history || [];
  const growth = calculateGrowthScore(history);
  const rating = ratings[exName];
  // Insufficient data → assume neutral (50)
  const growthScore = growth ? growth.score : 50;
  const enjoyScore = rating ? rating * 20 : 60; // unrated defaults to "slightly positive"
  return {
    score: Math.round(growthScore * 0.6 + enjoyScore * 0.4),
    growth,
    rating,
    hasData: growth !== null || rating !== undefined,
  };
}

// Profile-fit score adjustment for an exercise. Returns a delta to add to the
// base exercise score. Stays in roughly ±10 range so it nudges without overwhelming
// growth/rating signals. Profile is the user profile (sex, height, experience).
//
// Returns: { delta: number, reasons: string[] } where reasons explain the bias
// applied (useful for UI tooltips).
function profileFitScore(exName, profile) {
  const ex = EXERCISE_LIBRARY[exName];
  if (!ex) return { delta: 0, reasons: [] };
  let delta = 0;
  const reasons = [];

  // 1. Experience / complexity match (strongest signal)
  const exp = profile.experience || 3; // default to intermediate if not set
  const c = ex.complexity || 1;
  const expBonus = EXPERIENCE_BONUS[exp]?.[c] ?? 0;
  if (expBonus !== 0) {
    delta += expBonus;
    if (expBonus < -50) reasons.push(`Complex for level ${exp}`);
    else if (expBonus < 0) reasons.push(`Slightly advanced for level ${exp}`);
    else if (expBonus > 0) reasons.push(`Good challenge for level ${exp}`);
  }

  // 2. Height match — soft ±3 bias
  if (ex.heightHint && ex.heightHint !== "neutral") {
    const cat = getHeightCategory(profile);
    if (cat === ex.heightHint) {
      delta += 3;
      reasons.push(`Leverages your ${cat} frame`);
    } else if (cat !== "average" && cat !== ex.heightHint) {
      delta -= 2;
    }
  }

  // 3. Gender hint — soft ±2 bias. Designed to nudge, never exclude.
  if (ex.genderHint && ex.genderHint !== "neutral") {
    const userSex = profile.sex;
    if ((ex.genderHint === "female-lean" && userSex === "F") ||
        (ex.genderHint === "male-lean" && userSex === "M")) {
      delta += 2;
      // Don't surface gender as a reason in UI — it's a quiet prior, not a label
    } else if ((ex.genderHint === "female-lean" && userSex === "M") ||
               (ex.genderHint === "male-lean" && userSex === "F")) {
      delta -= 1; // very small disfavour
    }
  }

  return { delta, reasons };
}

// Filter: should this exercise be eligible for the user at all (hard cutoffs)?
function exerciseIsEligibleForUser(exName, profile) {
  const ex = EXERCISE_LIBRARY[exName];
  if (!ex) return true;
  const exp = profile.experience || 3;
  const c = ex.complexity || 1;
  const maxComplexity = EXPERIENCE_MAX_COMPLEXITY[exp] ?? 3;
  if (c > maxComplexity) return false;
  return true;
}

// Pick best alternative for an exercise given preferences and history.
// profile is optional but enables profile-fit scoring.
function pickBestAlternative(exName, lifts, ratings, unavailSet, mustNotInclude = [], profile = null) {
  const exData = EXERCISE_LIBRARY[exName];
  if (!exData?.alts) return null;
  const candidates = exData.alts
    .filter(alt => !unavailSet.has(alt) && !mustNotInclude.includes(alt))
    .filter(alt => !profile || exerciseIsEligibleForUser(alt, profile))
    .map(alt => {
      const base = calculateExerciseScore(alt, lifts, ratings);
      const fit = profile ? profileFitScore(alt, profile) : { delta: 0, reasons: [] };
      return {
        name: alt,
        ...base,
        score: base.score + fit.delta,
        fitReasons: fit.reasons,
      };
    })
    .sort((a, b) => b.score - a.score);
  return candidates[0] || null;
}

// preferences = { ratings: {}, unavailable: [], blockStartDate: ISO date string }
// ============================================================
// FATIGUE-AWARE REORDERING — bias session order based on user's lift data
// ============================================================
const FATIGUE_COMPOUND_SET = new Set([
  "Barbell Squat", "Romanian Deadlift", "Barbell Bench Press", "Overhead Press",
  "Barbell Row", "Pull-ups", "Leg Press", "Hack Squat", "Bulgarian Split Squat",
  "Dumbbell Bench Press", "Incline Dumbbell Press", "Dumbbell Shoulder Press",
  "Machine Shoulder Press", "Machine Chest Press", "Lat Pulldown", "Cable Row",
]);

// Compute a per-exercise fatigue score from lift history (0-100, higher = more fatiguing)
function computeFatigueScores(lifts) {
  const scores = {};
  for (const [name, data] of Object.entries(lifts || {})) {
    const sessions = data?.history || [];
    if (sessions.length < 2) { scores[name] = 0; continue; }
    let rirDropSum = 0, repDropSum = 0, lateFails = 0, lateOpps = 0, samples = 0;
    for (const s of sessions) {
      if (!s.sets || s.sets.length < 2) continue;
      const first = s.sets[0];
      const last = s.sets[s.sets.length - 1];
      rirDropSum += (first.rir ?? 2) - (last.rir ?? 0);
      repDropSum += (first.reps ?? 0) - (last.reps ?? 0);
      for (let i = 2; i < s.sets.length; i++) {
        lateOpps++;
        if ((s.sets[i].rir ?? 2) === 0) lateFails++;
      }
      samples++;
    }
    if (samples === 0) { scores[name] = 0; continue; }
    const avgRirDrop = rirDropSum / samples;
    const avgRepDrop = repDropSum / samples;
    const lateFailRate = lateOpps > 0 ? lateFails / lateOpps : 0;
    scores[name] = Math.min(100, Math.round(
      (Math.max(0, avgRirDrop) * 20) + (Math.max(0, avgRepDrop) * 8) + (lateFailRate * 60)
    ));
  }
  return scores;
}

// Reorder a session's exercises: compounds first (preserve their order),
// then isolations sorted by fatigue score descending (most fatiguing isolations first).
// Within compounds, also sort by fatigue desc — heaviest tax first while you're freshest.
function reorderForFatigue(exercises, fatigueScores) {
  const compounds = exercises.filter(e => FATIGUE_COMPOUND_SET.has(e.name));
  const isolations = exercises.filter(e => !FATIGUE_COMPOUND_SET.has(e.name));
  // Sort each group by fatigue score desc
  compounds.sort((a, b) => (fatigueScores[b.name] || 0) - (fatigueScores[a.name] || 0));
  isolations.sort((a, b) => (fatigueScores[b.name] || 0) - (fatigueScores[a.name] || 0));
  return [...compounds, ...isolations];
}

// Suggest set count reduction for high-fatigue exercises with consistent late-set failures
function suggestSetReduction(exerciseName, currentSets, lifts) {
  const data = lifts?.[exerciseName];
  if (!data?.history || data.history.length < 3 || currentSets < 4) return null;
  let lateFails = 0, lateOpps = 0;
  for (const s of data.history) {
    for (let i = 2; i < (s.sets?.length || 0); i++) {
      lateOpps++;
      if ((s.sets[i].rir ?? 2) === 0) lateFails++;
    }
  }
  const failRate = lateOpps > 0 ? lateFails / lateOpps : 0;
  if (failRate >= 0.5) return currentSets - 1;
  return null;
}

// Map onboarding focusArea labels to MUSCLE_GROUPS_FOR_FATIGUE values.
// Multi-mapping (same as analytics) — Arms covers both biceps and triceps, etc.
const FOCUS_TO_TRAINING_MUSCLES = {
  "Glutes": ["Glutes", "Legs", "Hamstrings"],
  "Quads": ["Quads", "Legs"],
  "Hamstrings": ["Hamstrings"],
  "Calves": ["Calves"],
  "Core": ["Core"],
  "Abs": ["Core"],
  "Chest": ["Chest"],
  "Back": ["Back"],
  "Shoulders": ["Shoulders"],
  "Arms": ["Biceps", "Triceps", "Forearms"],
  "Biceps": ["Biceps"],
  "Triceps": ["Triceps"],
  "Forearms": ["Forearms"],
  "Upper Body": ["Chest", "Back", "Shoulders", "Biceps", "Triceps", "Forearms"],
  "Lower Body": ["Quads", "Legs", "Hamstrings", "Glutes", "Calves"],
};

// Resolve profile.focusAreas to a Set of muscle group names that the plan should bias toward.
function resolveFocusMuscles(focusAreas) {
  const set = new Set();
  for (const area of focusAreas || []) {
    const muscles = FOCUS_TO_TRAINING_MUSCLES[area] || [];
    muscles.forEach(m => set.add(m));
  }
  return set;
}

function generatePlan(profile, preferences = {}, lifts = {}) {
  const split = SPLITS[profile.split] || SPLITS["Upper-Lower"];
  const baseSessions = split.slice(0, profile.daysPerWeek);
  const ratings = preferences.ratings || {};
  const unavail = new Set(preferences.unavailable || []);
  const blockSwaps = preferences.blockSwaps || {};
  const setOverrides = preferences.setOverrides || {}; // { exerciseName: setCount }
  const repRangeOverrides = preferences.repRangeOverrides || {}; // { exerciseName: "10-12" }
  const fatigueOptimised = preferences.fatigueOptimised !== false; // default ON
  const autoSetReduction = preferences.autoSetReduction === true; // default OFF (suggestion-only)
  const focusMuscles = resolveFocusMuscles(profile.focusAreas);
  const focusBiasEnabled = preferences.focusBiasEnabled !== false; // default ON

  // Pre-compute fatigue scores once per generation
  const fatigueScores = fatigueOptimised ? computeFatigueScores(lifts) : {};

  return baseSessions.map(s => {
    const exercises = s.exercises.map(ex => {
      // Apply block-level swap if one exists
      const effectiveName = blockSwaps[ex.name] || ex.name;
      let exercise = blockSwaps[ex.name] ? { ...ex, name: effectiveName, swappedFrom: ex.name, swapPersistent: true } : ex;

      // Then apply gym-level (always-unavailable) swaps
      const isUnavailable = unavail.has(exercise.name);
      const rating = ratings[exercise.name];
      const isHardLow = rating === 1;
      // Profile-fit check: if the exercise is above the user's experience level,
      // swap it out automatically (e.g. beginner shouldn't get Barbell Squat).
      const isTooComplex = !exerciseIsEligibleForUser(exercise.name, profile);

      if (isUnavailable || isHardLow || isTooComplex) {
        const replacement = pickBestAlternative(exercise.name, lifts, ratings, unavail, [], profile);
        if (replacement) {
          exercise = {
            ...exercise,
            name: replacement.name,
            swappedFrom: exercise.swappedFrom || exercise.name,
            swapReason: isUnavailable ? "unavailable" : isHardLow ? "low-rated" : "experience",
            fitReasons: replacement.fitReasons,
          };
        }
      } else {
        // Even when not swapping, record any positive fit reasons so the UI can show them
        const fit = profileFitScore(exercise.name, profile);
        if (fit.reasons.length > 0) exercise = { ...exercise, fitReasons: fit.reasons };
      }

      // Annotate with warmup sets from library (compound lifts get 2-3 warmup sets)
      const libData = EXERCISE_LIBRARY[exercise.name];
      if (libData?.warmupSets != null) {
        exercise = { ...exercise, warmupSets: libData.warmupSets };
      }

      // Apply set-count override (manual user choice)
      if (setOverrides[exercise.name]) {
        exercise = { ...exercise, sets: setOverrides[exercise.name] };
      } else if (autoSetReduction) {
        // Auto-apply fatigue-driven set reduction if enabled
        const suggested = suggestSetReduction(exercise.name, exercise.sets, lifts);
        if (suggested) {
          exercise = { ...exercise, sets: suggested, fatigueAdjusted: true };
        }
      } else {
        // Suggestion only — flag without changing
        const suggested = suggestSetReduction(exercise.name, exercise.sets, lifts);
        if (suggested) {
          exercise = { ...exercise, fatigueSetSuggestion: suggested };
        }
      }

      // Focus-area bias: +1 set on exercises targeting focus muscles, but
      // ONLY if the user hasn't manually overridden the count. Never go above 5 sets.
      if (focusBiasEnabled && focusMuscles.size > 0 && !setOverrides[exercise.name]) {
        const muscle = MUSCLE_GROUPS_FOR_FATIGUE[exercise.name];
        if (muscle && focusMuscles.has(muscle) && exercise.sets < 5) {
          exercise = { ...exercise, sets: exercise.sets + 1, focusBiased: true };
        }
      }

      // User rep-range override (e.g. switch "6-8" to "10-12")
      if (repRangeOverrides[exercise.name]) {
        exercise = { ...exercise, reps: repRangeOverrides[exercise.name], repsOverridden: true };
      }

      return exercise;
    });

    // Reorder by fatigue if enabled — needs to happen BEFORE intensification
    // because superset pairing depends on adjacency.
    let reordered = fatigueOptimised
      ? reorderForFatigue(exercises, fatigueScores)
      : exercises;

    // Apply user's manual ordering for this session if one exists.
    // The user's order takes priority over fatigue ordering.
    const userOrder = preferences.exerciseOrder?.[s.name];
    if (userOrder && Array.isArray(userOrder)) {
      const byName = new Map(reordered.map(ex => [ex.name, ex]));
      const ordered = [];
      // Place items in user's specified order
      for (const name of userOrder) {
        if (byName.has(name)) {
          ordered.push(byName.get(name));
          byName.delete(name);
        }
      }
      // Append any new exercises (e.g. swapped-in alternatives) that weren't in user's order
      for (const ex of byName.values()) ordered.push(ex);
      reordered = ordered;
    }

    // Apply engine-suggested supersets and dropsets to the final ordering.
    // Date stamp ensures per-session skip flags work correctly.
    const today = new Date().toISOString().split("T")[0];
    const finalExercises = applyIntensifications(reordered, profile, preferences, today);

    return { ...s, exercises: finalExercises };
  });
}

// Run end-of-block rotation: identify low-scoring exercises and swap them in `blockSwaps`
function runBlockRotation(profile, preferences, lifts) {
  const split = SPLITS[profile.split] || SPLITS["Upper-Lower"];
  const baseSessions = split.slice(0, profile.daysPerWeek);
  const ratings = preferences.ratings || {};
  const unavail = new Set(preferences.unavailable || []);

  const newSwaps = { ...(preferences.blockSwaps || {}) };
  const rotated = []; // { from, to, score, reason }

  // Score every base exercise in the plan
  const allBaseExercises = new Set();
  baseSessions.forEach(s => s.exercises.forEach(ex => allBaseExercises.add(ex.name)));

  for (const exName of allBaseExercises) {
    // Skip if already swapped or marked unavailable (handled by gym-level)
    if (newSwaps[exName] || unavail.has(exName)) continue;

    const score = calculateExerciseScore(exName, lifts, ratings);

    // Only rotate if we have meaningful data and score is poor
    if (!score.hasData) continue;
    if (score.score >= 50) continue; // 50+ = keep
    if (score.growth && score.growth.sessions < 4) continue; // need at least 4 sessions to judge

    // Try to find a clearly better alternative (profile-fit aware)
    const replacement = pickBestAlternative(exName, lifts, ratings, unavail, [], profile);
    if (!replacement) continue;
    if (replacement.score - score.score < 15) continue; // alternative needs to be meaningfully better

    newSwaps[exName] = replacement.name;
    rotated.push({
      from: exName,
      to: replacement.name,
      fromScore: score.score,
      toScore: replacement.score,
      reason: score.growth?.perSessionPct < 0.5
        ? "Low growth"
        : score.rating <= 2
          ? "Low enjoyment"
          : "Combined score",
    });
  }

  return { newSwaps, rotated };
}



function parseRepRange(repStr) {
  if (typeof repStr !== "string") return { bottom: 8, top: 12 };
  const m = repStr.match(/(\d+)\s*-\s*(\d+)/);
  if (m) return { bottom: parseInt(m[1]), top: parseInt(m[2]) };
  const single = parseInt(repStr);
  if (!isNaN(single)) return { bottom: single, top: single };
  return { bottom: 8, top: 12 };
}

// Detect timed exercises (e.g. "30-60s", "45s")
function isTimedExercise(exerciseName, repStr) {
  if (typeof repStr === "string" && repStr.toLowerCase().includes("s")) return true;
  // Plank-style exercises that are inherently timed
  if (["Plank"].includes(exerciseName)) return true;
  return false;
}

// Detect bodyweight-only exercises where weight input doesn't apply
function isBodyweightOnly(exerciseName) {
  const data = EXERCISE_LIBRARY[exerciseName];
  if (!data) return false;
  return data.equipment === "Bodyweight";
}

function getSetRecommendation(lastSet, range) {
  // Returns { type, weight, reps, message, action } where:
  // type: "level_up" | "drop" | "hold" | "push_reps"
  // weight, reps: suggested next-set values
  // message: user-facing reasoning
  // action: short call-to-action label
  if (lastSet.reps >= range.top && lastSet.rir >= 2) {
    return {
      type: "level_up",
      weight: lastSet.weight + 2.5,
      reps: range.top,
      rir: 2,
      message: `🚀 You smashed it — ${lastSet.reps} reps with ${lastSet.rir} in reserve. Bump the weight.`,
      action: `Try ${lastSet.weight + 2.5}kg`,
      tone: "level_up",
    };
  }
  if (lastSet.reps >= range.top && lastSet.rir >= 1) {
    return {
      type: "push_reps",
      weight: lastSet.weight,
      reps: lastSet.reps + 1,
      rir: 1,
      message: `Solid — ${lastSet.reps} reps with ${lastSet.rir} RIR. Stay at this weight, push for ${lastSet.reps + 1} reps next set.`,
      action: `${lastSet.weight}kg × ${lastSet.reps + 1}`,
      tone: "push",
    };
  }
  if (lastSet.reps < range.bottom && lastSet.rir <= 1) {
    return {
      type: "drop",
      weight: Math.max(0, lastSet.weight - 2.5),
      reps: range.bottom,
      rir: 2,
      message: `Too heavy — ${lastSet.reps} reps below the target ${range.bottom}-${range.top} range with low RIR. Drop the weight.`,
      action: `Drop to ${Math.max(0, lastSet.weight - 2.5)}kg`,
      tone: "drop",
    };
  }
  if (lastSet.reps < range.bottom && lastSet.rir >= 2) {
    return {
      type: "push_reps",
      weight: lastSet.weight,
      reps: range.bottom,
      rir: 2,
      message: `${lastSet.reps} reps but with ${lastSet.rir} in reserve — push harder, you've got more in the tank.`,
      action: `Aim for ${range.bottom} reps`,
      tone: "push",
    };
  }
  if (lastSet.rir === 0 && lastSet.reps <= range.bottom + 1) {
    return {
      type: "drop",
      weight: Math.max(0, lastSet.weight - 2.5),
      reps: range.bottom,
      rir: 2,
      message: `You hit failure low in the range. Drop the weight to keep good form.`,
      action: `Drop to ${Math.max(0, lastSet.weight - 2.5)}kg`,
      tone: "drop",
    };
  }
  // Within range, RIR sensible — hold
  return {
    type: "hold",
    weight: lastSet.weight,
    reps: lastSet.reps,
    rir: lastSet.rir,
    message: `Dialled in — ${lastSet.reps} reps with ${lastSet.rir} RIR sits well inside the target range. Repeat.`,
    action: `Repeat ${lastSet.weight}kg × ${lastSet.reps}`,
    tone: "hold",
  };
}

// Legacy — used in some places, kept for backward compat
function suggestNext(lastSet, range) {
  const rec = getSetRecommendation(lastSet, range);
  return { weight: rec.weight, reps: rec.reps, rir: rec.rir };
}

