// ============================================================
// CALC for clients (for PT view)
// ============================================================
const GOAL_DIRECTION = { "Cut": "cut", "Bulk": "bulk", "Lean Bulk": "bulk", "Recomp": "recomp", "Maintain": "maintain" };

function calculateTargets({ sex, age, dob, height, weight, activity, goal, targetWeight }) {
  if (!age && dob) { const b = new Date(dob); const n = new Date(); age = n.getFullYear() - b.getFullYear(); if (n.getMonth() < b.getMonth() || (n.getMonth() === b.getMonth() && n.getDate() < b.getDate())) age--; }
  age = age || 30;
  const w = weight || 1;
  const bmr = sex === "M" ? 10 * w + 6.25 * height - 5 * age + 5 : 10 * w + 6.25 * height - 5 * age - 161;
  const tdee = Math.round(bmr * activity);
  const direction = GOAL_DIRECTION[goal] || "maintain";
  // Standard rate: ~0.5%bw/wk
  let rate = 0;
  if (direction === "cut") rate = -(w * 0.005);
  else if (direction === "bulk") rate = w * 0.005;
  // recomp & maintain stay near 0
  const floor = sex === "M" ? 1500 : 1200;
  const calTarget = Math.max(floor, Math.round(tdee + (rate * 7700) / 7));
  let pPerKg, fPerKg;
  if (goal === "Cut") { pPerKg = 2.2; fPerKg = 0.8; }
  else if (goal === "Recomp") { pPerKg = 2.4; fPerKg = 0.9; }
  else if (direction === "bulk") { pPerKg = 1.8; fPerKg = 1.0; }
  else { pPerKg = 1.6; fPerKg = 0.9; }
  const protein = Math.round(w * pPerKg);
  const fat = Math.round(w * fPerKg);
  const carbs = Math.max(50, Math.round((calTarget - 4 * protein - 9 * fat) / 4));
  return { tdee, calTarget, protein, fat, carbs };
}

