export default function SINCTrainingApp() {
  const [seeding, setSeeding] = useState(true);
  const [seedStatus, setSeedStatus] = useState("Loading...");
  const [seedError, setSeedError] = useState(null);
  const [session, setSession] = useState(null);
  const themeCtx = useTheme();

  useEffect(() => {
    (async () => {
      try {
        await seedDemoIfNeeded(setSeedStatus);
        const s = await storage.get("sinc-session");
        if (s) setSession(s);
      } catch (e) {
        setSeedError(e.message || String(e));
      }
      setSeeding(false);
    })();
  }, []);

  if (seeding) {
    const isLight = !themeCtx.theme.bg.includes("950");
    return (
      <div className={`min-h-screen ${themeCtx.theme.bg} flex items-center justify-center px-5`}>
        <div className="text-center">
          <Wordmark height={64} inverted={isLight} />
          <div className={`mt-6 text-sm ${themeCtx.theme.textMuted}`}>{seedStatus}</div>
          {seedError ? (
            <div className="mt-3 bg-red-50 border border-red-200 text-red-700 text-xs rounded-lg p-3 max-w-xs">{seedError}</div>
          ) : (
            <div className="mt-3 w-8 h-8 border-4 border-slate-200 rounded-full animate-spin mx-auto" style={{ borderTopColor: ORANGE }} />
          )}
        </div>
      </div>
    );
  }

  if (!session) {
    return <TrainingAuth themeCtx={themeCtx} onAuth={async acc => {
      await storage.set("sinc-session", { id: acc.id, username: acc.username, role: acc.role });
      setSession({ id: acc.id, username: acc.username, role: acc.role });
    }} />;
  }

  const handleLogout = async () => { await storage.delete("sinc-session"); setSession(null); };
  return <TrainingApp session={session} themeCtx={themeCtx} onLogout={handleLogout} />;
}

