function TrainingApp({ session, themeCtx, onLogout }) {
  const { theme } = themeCtx;
  const [profile, setProfile] = useState(null);
  useEffect(() => { storage.get(userKey(session.id, "profile")).then(setProfile); }, [session.id]);
  if (!profile) return <div className={`min-h-screen ${theme.bg} flex items-center justify-center ${theme.textMuted} text-sm`}>Loading...</div>;
  const updateProfile = async (next) => {
    await storage.set(userKey(session.id, "profile"), next);
    setProfile(next);
  };
  return <TrainingMain session={session} profile={profile} updateProfile={updateProfile} themeCtx={themeCtx} onLogout={onLogout} />;
}

function TrainingMain({ session, profile, updateProfile, themeCtx, onLogout }) {
  const { theme, dark, toggle } = themeCtx;
  const [view, setView] = useState("week"); // week | session | exercise
  const [tab, setTab] = useState("training"); // training | exercises | more
  const [activeSessionIdx, setActiveSessionIdx] = useState(null);
  const [activeExercise, setActiveExercise] = useState(null);
  const [refresh, setRefresh] = useState(0);
  const [preferences, setPreferences] = useState({ ratings: {}, unavailable: [], blockSwaps: {}, blockStartDate: null });
  const [planOverrides, setPlanOverrides] = useState({ setOverrides: {}, weightHints: {}, repHints: {}, swapList: [], volumeNudges: {} });
  const [lifts, setLifts] = useState({});

  // Load preferences and lifts
  useEffect(() => {
    (async () => {
      const p = await storage.get(userKey(session.id, "exercise-prefs"));
      const initialPrefs = {
        ratings: p?.ratings || {},
        unavailable: p?.unavailable || [],
        blockSwaps: p?.blockSwaps || {},
        blockStartDate: p?.blockStartDate || new Date().toISOString().split("T")[0],
        blockLength: p?.blockLength || 4,
        supersets: p?.supersets || {},
      };
      // If no block start date was set, persist the default
      if (!p?.blockStartDate) {
        await storage.set(userKey(session.id, "exercise-prefs"), initialPrefs);
      }
      setPreferences(initialPrefs);
      const l = (await storage.get(userKey(session.id, "lifts"))) || {};
      setLifts(l);
      // Load accepted suggestions overrides written by Artifact 1's dashboard
      const overrides = (await storage.get(userKey(session.id, "plan-overrides"))) || {
        setOverrides: {}, weightHints: {}, repHints: {}, swapList: [], volumeNudges: {}
      };
      setPlanOverrides(overrides);
    })();
  }, [session.id, refresh]);

  // Merge persisted overrides into preferences before generation
  const effectivePrefs = useMemo(() => {
    const base = { ...preferences };
    if (planOverrides.setOverrides) {
      base.setOverrides = { ...(base.setOverrides || {}), ...planOverrides.setOverrides };
    }
    return base;
  }, [preferences, planOverrides]);

  const plan = useMemo(() => generatePlan(profile, effectivePrefs, lifts), [profile, effectivePrefs, lifts]);

  const savePreferences = async (next) => {
    setPreferences(next);
    await storage.set(userKey(session.id, "exercise-prefs"), next);
    setRefresh(r => r + 1);
  };

  const endBlock = async () => {
    const { newSwaps, rotated } = runBlockRotation(profile, preferences, lifts);
    const next = {
      ...preferences,
      blockSwaps: newSwaps,
      blockStartDate: new Date().toISOString().split("T")[0],
    };
    await savePreferences(next);
    return { rotated };
  };

  // Drill-down views ignore the tab nav
  if (view === "exercise" && activeExercise && activeSessionIdx !== null) {
    // If activeExercise is part of a superset, look up the partner from the session.
    // The logger then runs in "alternating" mode for both exercises.
    const session_data = plan[activeSessionIdx];
    let supersetPartner = null;
    if (activeExercise.supersetWith) {
      supersetPartner = session_data.exercises.find(e => e.name === activeExercise.supersetWith) || null;
    }
    return <ExerciseLogger key={refresh}
      session={session} profile={profile} exercise={activeExercise}
      supersetPartner={supersetPartner}
      sessionName={session_data.name}
      themeCtx={themeCtx}
      onBack={() => setView("session")}
      onComplete={() => { setRefresh(r => r + 1); setView("session"); }} />;
  }

  if (view === "session" && activeSessionIdx !== null) {
    return <SessionView key={refresh}
      session={session} profile={profile} sessionData={plan[activeSessionIdx]}
      sessionIdx={activeSessionIdx}
      themeCtx={themeCtx}
      preferences={preferences}
      onSavePreferences={savePreferences}
      onBack={() => setView("week")}
      onPick={ex => { setActiveExercise(ex); setView("exercise"); }} />;
  }

  return (
    <div className={`min-h-screen ${theme.bg} pb-20`}>
      <div className="max-w-md mx-auto">
        {tab === "training" && <WeekView session={session} profile={profile} updateProfile={updateProfile} plan={plan} preferences={preferences} lifts={lifts}
          themeCtx={themeCtx}
          onPick={i => { setActiveSessionIdx(i); setView("session"); }}
          onEndBlock={endBlock}
          onSavePreferences={savePreferences} />}
        {tab === "exercises" && <ExercisesTab session={session} profile={profile} plan={plan} preferences={preferences} lifts={lifts} themeCtx={themeCtx}
          onChange={p => { savePreferences({ ...preferences, ...p }); }} />}
        {tab === "more" && <MoreTab themeCtx={themeCtx} onLogout={onLogout} />}
      </div>
      <div className={`fixed bottom-0 left-0 right-0 ${theme.nav} border-t ${theme.navBorder}`}>
        <div className="max-w-md mx-auto grid grid-cols-3">
          <NavBtn icon="train" label="Training" active={tab === "training"} onClick={() => setTab("training")} theme={theme} />
          <NavBtn icon="exercises" label="Exercises" active={tab === "exercises"} onClick={() => setTab("exercises")} theme={theme} />
          <NavBtn icon="more" label="More" active={tab === "more"} onClick={() => setTab("more")} theme={theme} />
        </div>
      </div>
    </div>
  );
}

