function SessionCard({ session, sessionData, sessionIdx, theme, onClick }) {
  const [stats, setStats] = useState({ lastDate: null, doneThisWeek: false, doneOn: null });

  useEffect(() => {
    (async () => {
      const lifts = (await storage.get(userKey(session.id, "lifts"))) || {};
      let mostRecent = null;
      for (const ex of sessionData.exercises) {
        const last = lifts[ex.name]?.lastDate;
        if (last && (!mostRecent || last > mostRecent)) mostRecent = last;
      }

      // Check session-completions for this week
      const completions = (await storage.get(userKey(session.id, "session-completions"))) || {};
      const today = new Date();
      const day = today.getDay();
      const diff = today.getDate() - day + (day === 0 ? -6 : 1);
      const monday = new Date(today); monday.setDate(diff); monday.setHours(0, 0, 0, 0);
      let doneThisWeek = false;
      let doneOn = null;
      for (let i = 0; i < 7; i++) {
        const d = new Date(monday); d.setDate(d.getDate() + i);
        const ds = d.toISOString().split("T")[0];
        if (completions[ds]?.includes(sessionData.name)) {
          doneThisWeek = true;
          doneOn = ds;
          break;
        }
      }

      setStats({ lastDate: mostRecent, doneThisWeek, doneOn });
    })();
  }, [session.id, sessionData]);

  const lastLabel = stats.lastDate
    ? (() => {
        const d = new Date(stats.lastDate);
        const days = Math.floor((Date.now() - d.getTime()) / 86400000);
        if (days === 0) return "Today";
        if (days === 1) return "Yesterday";
        if (days < 7) return `${days}d ago`;
        return d.toLocaleDateString("en-GB", { day: "numeric", month: "short" });
      })()
    : "Not yet";

  const doneOnLabel = stats.doneOn
    ? new Date(stats.doneOn).toLocaleDateString("en-GB", { weekday: "short" })
    : "";

  return (
    <button onClick={onClick}
      className={`w-full rounded-2xl shadow-sm border-2 p-5 text-left active:opacity-80 ${stats.doneThisWeek ? "" : theme.card}`}
      style={{
        borderColor: stats.doneThisWeek ? "#10b981" : "",
        backgroundColor: stats.doneThisWeek ? "#f0fdf4" : "",
      }}>
      <div className="flex items-center justify-between mb-2">
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 mb-0.5">
            <div className={`text-[10px] uppercase tracking-wide font-bold ${stats.doneThisWeek ? "" : theme.textMuted}`}
              style={{ color: stats.doneThisWeek ? "#15803d" : "" }}>Day {sessionIdx + 1}</div>
            {stats.doneThisWeek && (
              <span className="text-[9px] font-bold px-1.5 py-0.5 rounded" style={{ backgroundColor: "#10b981", color: "white" }}>✓ DONE</span>
            )}
          </div>
          <h3 className={`text-lg font-bold ${stats.doneThisWeek ? "text-emerald-900" : theme.text}`}>{sessionData.name}</h3>
        </div>
        {stats.doneThisWeek ? (
          <div className="w-10 h-10 rounded-full flex items-center justify-center font-bold text-base" style={{ backgroundColor: "#10b981", color: "white" }}>✓</div>
        ) : (
          <div className="w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm" style={{ backgroundColor: `${ORANGE}15`, color: ORANGE }}>→</div>
        )}
      </div>
      <div className="flex items-center justify-between text-xs">
        <span className={stats.doneThisWeek ? "text-emerald-700" : theme.textMuted}>{sessionData.exercises.length} exercises</span>
        <span className={`font-medium ${stats.doneThisWeek ? "text-emerald-700" : theme.textMuted}`}>
          {stats.doneThisWeek ? `Done ${doneOnLabel}` : `Last: ${lastLabel}`}
        </span>
      </div>
    </button>
  );
}

function SessionView({ session, profile, sessionData, sessionIdx, themeCtx, onBack, onPick, preferences, onSavePreferences }) {
  const { theme } = themeCtx;
  const [lifts, setLifts] = useState({});

  useEffect(() => {
    storage.get(userKey(session.id, "lifts")).then(v => setLifts(v || {}));
  }, [session.id]);

  // Reorder mode — show up/down arrows on each exercise
  const [reorderMode, setReorderMode] = useState(false);

  // Move exercise (or superset pair) up or down by one slot in the session.
  // A paired pair (A+B) moves as a unit — we swap by 2 positions if i is A and i+1 is B,
  // or treat them as a single item being moved.
  const moveExercise = async (fromIdx, direction) => {
    if (!preferences || !onSavePreferences) return;
    const exs = [...sessionData.exercises];

    // Identify if fromIdx is part of a superset pair
    const item = exs[fromIdx];
    const isA = item.supersetRole === "A";
    const isB = item.supersetRole === "B";

    // Determine the "block" — either single exercise or A+B pair — being moved
    let blockStart, blockEnd;
    if (isA) { blockStart = fromIdx; blockEnd = fromIdx + 1; }
    else if (isB) { blockStart = fromIdx - 1; blockEnd = fromIdx; }
    else { blockStart = fromIdx; blockEnd = fromIdx; }
    const blockSize = blockEnd - blockStart + 1;

    // Determine target position. We swap with the adjacent "block" in the direction of motion.
    let targetStart;
    if (direction === "up") {
      if (blockStart === 0) return; // already at top
      const prev = exs[blockStart - 1];
      const prevIsA = prev.supersetRole === "A";
      const prevIsB = prev.supersetRole === "B";
      let prevBlockStart;
      if (prevIsB) prevBlockStart = blockStart - 2;
      else if (prevIsA) return; // shouldn't happen — A is always followed by B
      else prevBlockStart = blockStart - 1;
      targetStart = prevBlockStart;
    } else {
      if (blockEnd === exs.length - 1) return; // already at bottom
      const nextEx = exs[blockEnd + 1];
      const nextIsA = nextEx.supersetRole === "A";
      const nextIsB = nextEx.supersetRole === "B";
      let nextBlockEnd;
      if (nextIsA) nextBlockEnd = blockEnd + 2;
      else if (nextIsB) return; // shouldn't happen
      else nextBlockEnd = blockEnd + 1;
      targetStart = blockEnd + 1 - (blockSize - 1); // not used directly, see splice logic
      // For "down": we move our block to after the next block.
    }

    // Build new ordering by splicing
    const block = exs.splice(blockStart, blockSize);
    let insertAt;
    if (direction === "up") insertAt = targetStart;
    else {
      // After removing our block, the next block's start is now at blockStart (it shifted up by blockSize).
      // We want to insert after the next block — so its size after splice + blockStart.
      const adjacent = exs[blockStart]; // first item of what was the "next" block
      const adjacentIsA = adjacent.supersetRole === "A";
      const adjacentSize = adjacentIsA ? 2 : 1;
      insertAt = blockStart + adjacentSize;
    }
    exs.splice(insertAt, 0, ...block);

    // Persist new ordering by name list keyed on session name
    const order = exs.map(e => e.name);
    const exerciseOrder = { ...(preferences.exerciseOrder || {}) };
    exerciseOrder[sessionData.name] = order;
    await onSavePreferences({ ...preferences, exerciseOrder });
  };

  // Clear any custom ordering for this session (revert to engine's order)
  const resetOrder = async () => {
    if (!preferences || !onSavePreferences) return;
    const exerciseOrder = { ...(preferences.exerciseOrder || {}) };
    delete exerciseOrder[sessionData.name];
    await onSavePreferences({ ...preferences, exerciseOrder });
  };

  // Toggle superset pairing between exercise i and i+1 (next in list)
  const toggleSuperset = async (i) => {
    if (!preferences || !onSavePreferences) return;
    const ex = sessionData.exercises[i];
    const next = sessionData.exercises[i + 1];
    if (!next) return;
    const current = preferences.supersets || {};
    const isPaired = current[ex.name] === next.name || current[next.name] === ex.name;
    const updated = { ...current };
    if (isPaired) {
      delete updated[ex.name];
      delete updated[next.name];
    } else {
      // Clear any existing pairs involving either exercise
      Object.keys(updated).forEach(k => {
        if (k === ex.name || k === next.name || updated[k] === ex.name || updated[k] === next.name) {
          delete updated[k];
        }
      });
      updated[ex.name] = next.name;
    }
    await onSavePreferences({ ...preferences, supersets: updated });
  };

  // Skip an engine-suggested superset for today only. Stores per-date flag.
  const skipEngineSuperset = async (aName, bName) => {
    if (!preferences || !onSavePreferences) return;
    const today = new Date().toISOString().split("T")[0];
    const skips = { ...(preferences.skipIntensification || {}) };
    skips[`superset:${aName}+${bName}:${today}`] = true;
    await onSavePreferences({ ...preferences, skipIntensification: skips });
  };

  // Skip an engine-suggested dropset for today only.
  const skipEngineDropset = async (exName) => {
    if (!preferences || !onSavePreferences) return;
    const today = new Date().toISOString().split("T")[0];
    const skips = { ...(preferences.skipIntensification || {}) };
    skips[`dropset:${exName}:${today}`] = true;
    await onSavePreferences({ ...preferences, skipIntensification: skips });
  };

  const today = new Date().toISOString().split("T")[0];
  const completedToday = sessionData.exercises.filter(ex => lifts[ex.name]?.lastDate === today).length;
  const allDone = completedToday === sessionData.exercises.length && completedToday > 0;

  // Session-level: how many exercises beat last week's volume?
  const sessionStats = useMemo(() => {
    if (!allDone) return null;
    let beats = 0, matches = 0, misses = 0, currentTotal = 0, lastTotal = 0;
    sessionData.exercises.forEach(ex => {
      const exData = lifts[ex.name];
      if (!exData) return;
      const todaySets = exData.lastSession || [];
      const todayVol = todaySets.reduce((s, set) => s + set.weight * set.reps, 0);
      // Find prior session (second to last in history)
      const history = exData.history || [];
      const prior = history.length >= 2 ? history[history.length - 2] : null;
      const priorVol = prior ? prior.sets.reduce((s, set) => s + set.weight * set.reps, 0) : 0;
      currentTotal += todayVol;
      lastTotal += priorVol;
      if (priorVol === 0) return;
      if (todayVol > priorVol * 1.02) beats++;
      else if (todayVol < priorVol * 0.98) misses++;
      else matches++;
    });
    return { beats, matches, misses, currentTotal, lastTotal };
  }, [allDone, sessionData, lifts]);

  return (
    <div className={`min-h-screen ${theme.bg} pb-4`}>
      <div className="max-w-md mx-auto">
        <div className="px-5 pt-10 pb-6 text-white relative overflow-hidden" style={{ background: `linear-gradient(135deg, ${theme.headerStart}, ${theme.headerEnd})` }}>
          <img src={HERO_SQUAT_B64} alt="" className="absolute inset-0 w-full h-full object-cover" style={{ opacity: 0.28, mixBlendMode: "luminosity" }} />
          <div className="relative">
            <button onClick={onBack} className="text-blue-100 text-sm flex items-center gap-1 mb-3">← Back</button>
            <h1 className="text-2xl font-bold">{sessionData.name}</h1>
            <p className="text-blue-100 text-sm mt-1">{completedToday}/{sessionData.exercises.length} done today</p>
            {completedToday > 0 && (
              <div className="mt-3 h-1.5 bg-blue-800/40 rounded-full overflow-hidden">
                <div className="h-full transition-all" style={{ width: `${(completedToday / sessionData.exercises.length) * 100}%`, backgroundColor: ORANGE }} />
              </div>
            )}
          </div>
        </div>

        {/* Reorder toggle row */}
        {onSavePreferences && (
          <div className="px-4 mt-3 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <button onClick={() => setReorderMode(!reorderMode)}
                className="text-[11px] font-semibold px-3 py-1.5 rounded-lg flex items-center gap-1.5"
                style={{
                  backgroundColor: reorderMode ? ORANGE : (theme.bg.includes("950") ? "#1e293b" : "#f1f5f9"),
                  color: reorderMode ? "white" : (theme.bg.includes("950") ? "#cbd5e1" : "#475569"),
                }}>
                {reorderMode ? "✓ Done reordering" : "⇅ Reorder"}
              </button>
              {preferences?.exerciseOrder?.[sessionData.name] && (
                <button onClick={resetOrder}
                  className={`text-[10px] underline ${theme.textMuted}`}>
                  Reset to suggested
                </button>
              )}
            </div>
            {reorderMode && (
              <span className={`text-[10px] ${theme.textMuted} italic`}>Pairs move together</span>
            )}
          </div>
        )}

        <div className="px-4 mt-2 space-y-2">
          {sessionData.exercises.map((ex, i) => {
            const exData = lifts[ex.name];
            const lastSets = exData?.lastSession || [];
            const lastVol = lastSets.reduce((s, set) => s + set.weight * set.reps, 0);
            const lastWt = lastSets[0]?.weight;
            const doneToday = exData?.lastDate === today;
            const next = sessionData.exercises[i + 1];
            const isPairedToNext = ex.supersetWith && ex.supersetWith === next?.name;
            const isPairedFromPrev = i > 0 && sessionData.exercises[i - 1].supersetWith === ex.name;
            return (
              <Fragment key={i}>
                <div
                  role="button"
                  tabIndex={0}
                  onClick={() => { if (!reorderMode) onPick(ex); }}
                  className={`w-full p-4 rounded-xl border-2 flex items-center gap-3 text-left cursor-pointer ${reorderMode ? "" : "active:opacity-80"} ${theme.card}`}
                  style={{
                    borderColor: doneToday ? "#86efac" : reorderMode ? `${ORANGE}88` : (isPairedToNext || isPairedFromPrev) ? `${ORANGE}55` : "",
                    backgroundColor: doneToday ? "#f0fdf4" : "",
                    // Connect visually with previous exercise when this is the B-side
                    marginTop: isPairedFromPrev ? "-8px" : "",
                    borderTopLeftRadius: isPairedFromPrev ? "0" : "",
                    borderTopRightRadius: isPairedFromPrev ? "0" : "",
                    borderBottomLeftRadius: isPairedToNext ? "0" : "",
                    borderBottomRightRadius: isPairedToNext ? "0" : "",
                  }}>
                  {doneToday ? (
                    <div className="w-10 h-10 rounded-full flex items-center justify-center font-bold text-base flex-shrink-0" style={{ backgroundColor: "#10b981", color: "white" }}>✓</div>
                  ) : (
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm flex-shrink-0 ${theme.surface} ${theme.surfaceText}`}>
                      {isPairedFromPrev ? "B" : isPairedToNext ? "A" : i + 1}
                    </div>
                  )}
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-1.5 flex-wrap">
                      <div className={`font-semibold truncate ${doneToday ? "text-emerald-900" : theme.text}`}>{ex.name}</div>
                      {ex.swappedFrom && (
                        <span className="text-[9px] font-bold px-1.5 py-0.5 rounded flex-shrink-0" style={{ backgroundColor: `${ORANGE}33`, color: ORANGE }}>SWAP</span>
                      )}
                      {(isPairedToNext || isPairedFromPrev) && (
                        <span className="text-[9px] font-bold px-1.5 py-0.5 rounded flex-shrink-0" style={{ backgroundColor: `${ORANGE}33`, color: ORANGE }}>SUPERSET</span>
                      )}
                      {ex.dropsetSuggested && (
                        <span className="text-[9px] font-bold px-1.5 py-0.5 rounded flex-shrink-0" style={{ backgroundColor: "#15803d33", color: "#15803d" }} title={ex.dropsetSuggested.reason}>+ DROPSET</span>
                      )}
                      {ex.fatigueAdjusted && (
                        <span className="text-[9px] font-bold px-1.5 py-0.5 rounded flex-shrink-0" style={{ backgroundColor: "#10b98133", color: "#10b981" }}>−1 SET</span>
                      )}
                      {ex.fatigueSetSuggestion && !ex.fatigueAdjusted && (
                        <span className="text-[9px] font-bold px-1.5 py-0.5 rounded flex-shrink-0" style={{ backgroundColor: `${ORANGE}33`, color: ORANGE }} title="Fatigue insight: try fewer sets">TRY {ex.fatigueSetSuggestion}</span>
                      )}
                    </div>
                    {ex.swappedFrom && (
                      <div className={`text-[10px] ${theme.textMuted} mt-0.5 italic`}>was {ex.swappedFrom}</div>
                    )}
                    <div className={`text-xs mt-0.5 ${doneToday ? "text-emerald-700" : theme.textMuted}`}>
                      {doneToday ? (
                        `Done · ${Math.round(lastVol)}kg total volume`
                      ) : (
                        <>
                          {EXERCISE_LIBRARY[ex.name]?.equipment && <span className="font-medium">{EXERCISE_LIBRARY[ex.name].equipment}</span>}
                          <span className="mx-1.5">·</span>
                          {ex.sets} × {ex.reps}
                          {lastWt !== undefined && <span className="ml-2">· last {lastWt}kg</span>}
                          {lastVol > 0 && <span className="ml-2">· {Math.round(lastVol)}kg vol</span>}
                        </>
                      )}
                    </div>
                  </div>
                  {reorderMode ? (
                    <div className="flex flex-col gap-1" onClick={e => e.stopPropagation()}>
                      <button
                        onClick={(e) => { e.stopPropagation(); moveExercise(i, "up"); }}
                        disabled={i === 0 || (isPairedFromPrev && i === 1)}
                        className="w-8 h-8 rounded-lg font-bold flex items-center justify-center disabled:opacity-30"
                        style={{ backgroundColor: `${ORANGE}22`, color: ORANGE }}>
                        ▲
                      </button>
                      <button
                        onClick={(e) => { e.stopPropagation(); moveExercise(i, "down"); }}
                        disabled={i === sessionData.exercises.length - 1 || (isPairedToNext && i === sessionData.exercises.length - 2)}
                        className="w-8 h-8 rounded-lg font-bold flex items-center justify-center disabled:opacity-30"
                        style={{ backgroundColor: `${ORANGE}22`, color: ORANGE }}>
                        ▼
                      </button>
                    </div>
                  ) : (
                    <div style={{ color: doneToday ? "#10b981" : ORANGE }}>{doneToday ? "↻" : "→"}</div>
                  )}
                </div>

                {/* Superset action — varies by who paired this:
                    - engine-paired: show "Split out" to dismiss this session's pair
                    - unpaired: show subtle "Suggest superset?" (manual pin)
                    - user-paired: show "Unpair"
                    Hidden when this exercise is already done OR in reorder mode. */}
                {next && onSavePreferences && !doneToday && !reorderMode && (
                  <div className="flex justify-center -my-1 relative z-10">
                    {isPairedToNext ? (
                      <div className="flex items-center gap-1.5">
                        <button onClick={() => toggleSuperset(i)}
                          className="text-[9px] font-bold uppercase tracking-wider px-2.5 py-1 rounded-full"
                          style={{ backgroundColor: ORANGE, color: "white", border: `1px solid ${ORANGE}` }}>
                          ↕ Linked (A→B)
                        </button>
                        {ex.supersetSource === "engine" && (
                          <button onClick={() => skipEngineSuperset(ex.name, next.name)}
                            className={`text-[9px] font-semibold px-2 py-1 rounded-full ${theme.surface} ${theme.surfaceText}`}
                            title="Split out — do these as straight sets today">
                            Split out
                          </button>
                        )}
                      </div>
                    ) : (
                      <button onClick={() => toggleSuperset(i)}
                        className="text-[9px] font-semibold uppercase tracking-wider px-2.5 py-1 rounded-full"
                        style={{
                          backgroundColor: theme.bg.includes("950") ? "#1e293b" : "#f1f5f9",
                          color: theme.textMuted.includes("400") ? "#94a3b8" : "#64748b",
                          border: "1px solid transparent",
                        }}>
                        + Pin as superset
                      </button>
                    )}
                  </div>
                )}
              </Fragment>
            );
          })}
        </div>

        {/* Session complete celebration */}
        {allDone && sessionStats && (
          <div className="px-4 mt-4">
            <SessionCompleteCard stats={sessionStats} sessionName={sessionData.name} theme={theme} />
          </div>
        )}

        {/* Complete session button — always available */}
        <div className="px-4 mt-4 pb-4">
          <CompleteSessionButton
            session={session}
            sessionData={sessionData}
            completedToday={completedToday}
            theme={theme}
            onBack={onBack} />
        </div>
      </div>
    </div>
  );
}

function CompleteSessionButton({ session, sessionData, completedToday, theme, onBack }) {
  const [done, setDone] = useState(false);
  const [confirming, setConfirming] = useState(false);
  const today = new Date().toISOString().split("T")[0];

  // Check if already marked complete today
  useEffect(() => {
    (async () => {
      const completions = (await storage.get(userKey(session.id, "session-completions"))) || {};
      if (completions[today]?.includes(sessionData.name)) setDone(true);
    })();
  }, [session.id, sessionData.name]);

  const allDone = completedToday === sessionData.exercises.length;

  const doMarkComplete = async () => {
    const completions = (await storage.get(userKey(session.id, "session-completions"))) || {};
    if (!completions[today]) completions[today] = [];
    if (!completions[today].includes(sessionData.name)) {
      completions[today].push(sessionData.name);
    }
    await storage.set(userKey(session.id, "session-completions"), completions);

    const logs = (await storage.get(userKey(session.id, "logs"))) || {};
    if (!logs[today]) logs[today] = { food: false, weight: false, steps: false, workout: false };
    logs[today].workout = true;
    await storage.set(userKey(session.id, "logs"), logs);

    // Generate progression suggestions for this session's exercises
    try {
      const lifts = (await storage.get(userKey(session.id, "lifts"))) || {};
      const profile = (await storage.get(userKey(session.id, "profile"))) || {};
      const suggestions = analyseProgress(lifts, profile, [sessionData]);
      if (suggestions.length > 0) {
        const stored = (await storage.get(userKey(session.id, "suggestions"))) || { pending: [], accepted: [], rejected: [] };
        // Dedup: don't add suggestions for exercises that already have a pending one
        const pendingNames = new Set(stored.pending.map(s => s.exerciseName));
        const newOnes = suggestions
          .filter(s => !pendingNames.has(s.exerciseName))
          .map(s => ({ ...s, id: `${s.exerciseName}-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`, createdAt: today }));
        stored.pending.push(...newOnes);
        await storage.set(userKey(session.id, "suggestions"), stored);
      }
    } catch (e) { /* non-fatal */ }

    setDone(true);
    setTimeout(() => onBack && onBack(), 800);
  };

  const handleClick = () => {
    if (allDone) doMarkComplete();
    else setConfirming(true);
  };

  if (done) {
    return (
      <div className="rounded-2xl border-2 p-5 text-center" style={{ borderColor: "#10b981", backgroundColor: "#f0fdf4" }}>
        <div className="text-4xl mb-2">✅</div>
        <div className="font-bold text-emerald-900">{sessionData.name} complete</div>
        <div className="text-xs text-emerald-700 mt-1">Logged for {new Date(today).toLocaleDateString("en-GB", { weekday: "short", day: "numeric", month: "short" })}</div>
      </div>
    );
  }

  if (confirming) {
    return (
      <div className="rounded-2xl border-2 p-5" style={{ borderColor: ORANGE, backgroundColor: `${ORANGE}10` }}>
        <div className="text-center mb-4">
          <div className="mb-2 flex justify-center"><BrandIcon name="warning" size={28} color={ORANGE} strokeWidth={1.6} /></div>
          <div className={`font-bold text-base ${theme.text}`}>Only {completedToday} of {sessionData.exercises.length} exercises logged</div>
          <p className="text-xs mt-1" style={{ color: "#92400e" }}>Mark session complete anyway?</p>
        </div>
        <div className="grid grid-cols-2 gap-2">
          <button onClick={() => setConfirming(false)} className={`h-12 ${theme.surface} ${theme.surfaceText} rounded-xl font-semibold text-sm`}>
            ← Cancel
          </button>
          <button onClick={doMarkComplete} className="h-12 rounded-xl font-bold text-white" style={{ backgroundColor: ORANGE }}>
            Yes, complete
          </button>
        </div>
      </div>
    );
  }

  return (
    <button onClick={handleClick}
      className="w-full h-14 rounded-xl font-bold text-base text-white"
      style={{ backgroundColor: allDone ? "#10b981" : NAVY }}>
      {allDone ? "✅ Mark session complete" : `Complete session (${completedToday}/${sessionData.exercises.length})`}
    </button>
  );
}

// ============================================================
// TIMER INPUT — for timed exercises (Plank etc.)
// ============================================================
function TimerInput({ value, setValue, target, theme }) {
  const [running, setRunning] = useState(false);
  const [elapsed, setElapsed] = useState(0);

  useEffect(() => {
    if (!running) return;
    const start = Date.now() - elapsed * 1000;
    const id = setInterval(() => {
      setElapsed(Math.floor((Date.now() - start) / 1000));
    }, 100);
    return () => clearInterval(id);
  }, [running]);

  const stop = () => {
    setRunning(false);
    setValue(elapsed);
  };

  const reset = () => {
    setRunning(false);
    setElapsed(0);
    setValue(0);
  };

  const display = running ? elapsed : value;
  const targetReached = target > 0 && display >= target;

  return (
    <div className="mb-3">
      <label className={`block text-xs ${theme.textSubtle} mb-2`}>Hold time</label>
      <div className={`${theme.surface} rounded-xl p-5 text-center mb-2`}>
        <div className="text-5xl font-bold tabular-nums" style={{ color: targetReached ? "#10b981" : theme.text === "text-slate-100" ? "white" : "#0f172a" }}>
          {display}<span className="text-2xl">s</span>
        </div>
        {target > 0 && (
          <div className={`text-[10px] mt-1 ${theme.textMuted}`}>
            target: {target}s {targetReached && "· ✅"}
          </div>
        )}
      </div>
      <div className="grid grid-cols-2 gap-2">
        {!running && elapsed === 0 && (
          <button onClick={() => setRunning(true)} className="col-span-2 h-12 text-white rounded-lg font-bold" style={{ backgroundColor: "#10b981" }}>
            ▶️ Start timer
          </button>
        )}
        {running && (
          <button onClick={stop} className="col-span-2 h-12 text-white rounded-lg font-bold" style={{ backgroundColor: ORANGE }}>
            ⏸ Stop · log {elapsed}s
          </button>
        )}
        {!running && elapsed > 0 && (
          <>
            <button onClick={() => setRunning(true)} className="h-11 rounded-lg font-semibold text-sm text-white" style={{ backgroundColor: "#10b981" }}>
              ▶️ Resume
            </button>
            <button onClick={reset} className={`h-11 rounded-lg font-semibold text-sm ${theme.surface} ${theme.surfaceText}`}>
              Reset
            </button>
          </>
        )}
      </div>
      <div className={`flex items-center justify-between mt-3 px-2 text-[10px] ${theme.textMuted}`}>
        <span>Or enter manually:</span>
        <div className="flex items-center gap-2">
          <button onClick={() => { setValue(Math.max(0, value - 5)); setElapsed(0); }} className={`w-7 h-7 ${theme.card} rounded font-bold`}>−5</button>
          <span className={`text-xs font-bold w-10 text-center ${theme.text}`}>{value}s</span>
          <button onClick={() => { setValue(value + 5); setElapsed(0); }} className={`w-7 h-7 ${theme.card} rounded font-bold`}>+5</button>
        </div>
      </div>
    </div>
  );
}

// ============================================================
// CALIBRATION MODAL — first time user does an exercise
// ============================================================
function CalibrationModal({ exercise, profile, theme, onClose, onConfirm }) {
  const [step, setStep] = useState("intro"); // intro | direct | test | confirm
  const [knownWeight, setKnownWeight] = useState(0);
  const [testWeight, setTestWeight] = useState(0);
  const [testRound, setTestRound] = useState(0);

  const muscle = EXERCISE_LIBRARY[exercise.name]?.muscle;
  const repRange = parseRepRange(exercise.reps);

  // Sensible starting suggestions by muscle group + sex + bodyweight
  const suggestStartingWeight = () => {
    const bw = profile.weight || 70;
    const isM = profile.sex === "M";
    if (muscle === "Chest") return isM ? Math.round(bw * 0.5 / 2.5) * 2.5 : Math.round(bw * 0.3 / 2.5) * 2.5;
    if (muscle === "Back") return isM ? Math.round(bw * 0.6 / 2.5) * 2.5 : Math.round(bw * 0.4 / 2.5) * 2.5;
    if (muscle === "Legs" || muscle === "Quads") return isM ? Math.round(bw * 0.8 / 2.5) * 2.5 : Math.round(bw * 0.5 / 2.5) * 2.5;
    if (muscle === "Shoulders") return isM ? Math.round(bw * 0.3 / 2.5) * 2.5 : Math.round(bw * 0.2 / 2.5) * 2.5;
    if (muscle === "Biceps" || muscle === "Triceps") return isM ? 10 : 5;
    return isM ? 20 : 10;
  };

  const startSuggestion = suggestStartingWeight();

  // Test sequence: starts at 50% of suggestion, adjusts based on feedback
  const handleFeedback = (feel) => {
    if (feel === "right") {
      setStep("confirm");
    } else if (feel === "light") {
      const nextWeight = testWeight === 0 ? startSuggestion : testWeight + 5;
      setTestWeight(nextWeight);
      setTestRound(testRound + 1);
      if (testRound >= 3) setStep("confirm");
    } else if (feel === "heavy") {
      const nextWeight = Math.max(2.5, (testWeight === 0 ? startSuggestion : testWeight) - 5);
      setTestWeight(nextWeight);
      setTestRound(testRound + 1);
      if (testRound >= 3) setStep("confirm");
    }
  };

  const startTest = () => {
    setTestWeight(Math.round(startSuggestion * 0.6 / 2.5) * 2.5);
    setStep("test");
  };

  const finalWeight = testWeight > 0 ? testWeight : knownWeight;

  if (step === "intro") {
    return (
      <Modal title="Let's find your weight" onClose={onClose} theme={theme}>
        <div className="text-center mb-4">
          <div className="mb-2 flex justify-center"><BrandIcon name="workout" size={32} color={ORANGE} strokeWidth={1.6} /></div>
          <h3 className={`font-bold ${theme.text}`}>{exercise.name}</h3>
          <p className={`text-xs ${theme.textMuted} mt-2`}>First time logging this exercise. Let's get your starting weight right so progressive overload works from session 1.</p>
        </div>

        <div className="space-y-2 mb-4">
          <button onClick={() => setStep("direct")}
            className={`w-full p-4 rounded-xl border-2 text-left active:opacity-80 ${theme.card}`}
            style={{ borderColor: ORANGE }}>
            <div className="font-bold text-base" style={{ color: ORANGE }}>I know my weight</div>
            <p className={`text-xs ${theme.textMuted} mt-1`}>Enter the weight you usually use for {muscle?.toLowerCase()} work.</p>
          </button>
          <button onClick={startTest}
            className={`w-full p-4 rounded-xl border-2 text-left active:opacity-80 ${theme.card} ${theme.border}`}>
            <div className={`font-bold text-base ${theme.text}`}>Run a quick test</div>
            <p className={`text-xs ${theme.textMuted} mt-1`}>Try weights, tell me how they feel. We'll find the right one in 2-3 rounds.</p>
          </button>
        </div>

        <button onClick={onClose} className={`w-full h-11 ${theme.surface} ${theme.surfaceText} rounded-xl text-xs font-semibold`}>Skip — I'll figure it out</button>
      </Modal>
    );
  }

  if (step === "direct") {
    return (
      <Modal title="Starting weight" onClose={onClose} theme={theme}>
        <p className={`text-xs ${theme.textMuted} mb-4`}>
          What weight can you do for {repRange.bottom}-{repRange.top} reps? Suggestion based on your bodyweight: <span className="font-bold" style={{ color: ORANGE }}>{startSuggestion}kg</span>
        </p>
        <NumInput label="Weight" value={knownWeight === 0 ? startSuggestion : knownWeight} setValue={setKnownWeight} suffix="kg" step={2.5} theme={theme} />
        <div className="grid grid-cols-2 gap-2 mt-4">
          <button onClick={() => setStep("intro")} className={`h-12 ${theme.surface} ${theme.surfaceText} rounded-xl font-semibold`}>← Back</button>
          <button onClick={() => onConfirm(knownWeight === 0 ? startSuggestion : knownWeight)} className="h-12 text-white rounded-xl font-semibold" style={{ backgroundColor: ORANGE }}>Use this →</button>
        </div>
      </Modal>
    );
  }

  if (step === "test") {
    return (
      <Modal title={`Test round ${testRound + 1}`} onClose={onClose} theme={theme}>
        <div className="text-center mb-4">
          <div className="text-[10px] font-bold uppercase tracking-wide" style={{ color: ORANGE }}>Try this weight</div>
          <div className="text-5xl font-bold mt-2" style={{ color: ORANGE }}>{testWeight}<span className="text-2xl">kg</span></div>
          <p className={`text-xs ${theme.textMuted} mt-2`}>Aim for {repRange.bottom}-{repRange.top} reps. Then come back and tell me how it felt.</p>
        </div>

        <div className="space-y-2 mb-3">
          <button onClick={() => handleFeedback("light")} className="w-full p-3 rounded-xl text-white font-semibold" style={{ backgroundColor: "#10b981" }}>
            🪶 Too light · I had loads left
          </button>
          <button onClick={() => handleFeedback("right")} className="w-full p-3 rounded-xl text-white font-semibold" style={{ backgroundColor: ORANGE }}>
            ✅ Just right · hit the rep range
          </button>
          <button onClick={() => handleFeedback("heavy")} className="w-full p-3 rounded-xl text-white font-semibold" style={{ backgroundColor: NAVY }}>
            🪨 Too heavy · couldn't hit the reps
          </button>
        </div>

        <button onClick={() => setStep("intro")} className={`w-full h-11 ${theme.surface} ${theme.surfaceText} rounded-xl text-xs font-semibold`}>← Back</button>
      </Modal>
    );
  }

  // confirm
  return (
    <Modal title="✓ Starting weight set" onClose={onClose} theme={theme}>
      <div className="text-center mb-4">
        <div className="mb-2 flex justify-center"><BrandIcon name="target" size={36} color={ORANGE} strokeWidth={1.6} /></div>
        <p className={`text-sm ${theme.textMuted}`}>Your starting weight for</p>
        <h3 className={`text-lg font-bold ${theme.text} mt-1`}>{exercise.name}</h3>
        <div className="text-4xl font-bold mt-3" style={{ color: ORANGE }}>{finalWeight}kg</div>
      </div>
      <p className={`text-xs ${theme.textMuted} mb-4 text-center`}>From here, SINC will adapt every set based on your reps and RIR.</p>
      <button onClick={() => onConfirm(finalWeight)} className="w-full h-12 text-white rounded-xl font-semibold" style={{ backgroundColor: ORANGE }}>Let's go →</button>
    </Modal>
  );
}

function SessionCompleteCard({ stats, sessionName, theme }) {
  const { beats, matches, misses, currentTotal, lastTotal } = stats;
  const beatTotal = currentTotal > lastTotal && lastTotal > 0;
  const totalDiff = currentTotal - lastTotal;
  const totalPct = lastTotal > 0 ? Math.round((totalDiff / lastTotal) * 100) : 0;

  let tone, headline, message;
  if (beats >= matches + misses && beats > 0) {
    tone = "win";
    headline = `🏆 ${sessionName} smashed`;
    message = beatTotal
      ? `Beat ${beats} of your last numbers. Total volume up ${Math.round(totalDiff).toLocaleString()}kg (${totalPct}%) on last week.`
      : `Beat ${beats} exercises individually. Sustained progression — keep this energy.`;
  } else if (beatTotal) {
    tone = "win";
    headline = "Session beats last week";
    message = `Total volume up ${Math.round(totalDiff).toLocaleString()}kg overall, even with mixed exercise results. Real progression.`;
  } else if (matches > beats + misses) {
    tone = "match";
    headline = "🤝 Solid maintain";
    message = `Most exercises matched last week. Consistency is half the battle. Aim for one more rep next session.`;
  } else if (misses > beats) {
    tone = "miss";
    headline = "Session logged";
    message = `Bit of a tough one — fell short on ${misses} ${misses === 1 ? "exercise" : "exercises"}. Sleep, food, stress all matter. Show up next week.`;
  } else {
    tone = "neutral";
    headline = "✓ Done";
    message = `Beat ${beats}, matched ${matches}, fell short on ${misses}. Mixed bag — review which exercises stalled.`;
  }

  const bg = tone === "win" ? "#f0fdf4" : tone === "match" ? `${ORANGE}10` : tone === "miss" ? "#f8fafc" : `${NAVY}08`;
  const borderColor = tone === "win" ? "#86efac" : tone === "match" ? `${ORANGE}55` : tone === "miss" ? "#cbd5e1" : `${NAVY}33`;
  const textColor = tone === "win" ? "#14532d" : tone === "match" ? "#92400e" : tone === "miss" ? "#475569" : "#0f172a";

  return (
    <div className="rounded-2xl border-2 p-5 text-center" style={{ backgroundColor: bg, borderColor }}>
      <h3 className="text-lg font-bold mb-2" style={{ color: textColor }}>{headline}</h3>
      <p className="text-sm leading-relaxed mb-3" style={{ color: textColor }}>{message}</p>
      {beats + matches + misses > 0 && (
        <div className="flex justify-center gap-3 text-xs">
          <span className="font-bold" style={{ color: "#10b981" }}>{beats} 🏆</span>
          <span className="font-bold" style={{ color: ORANGE }}>{matches} 🤝</span>
          <span className="font-bold" style={{ color: "#ef4444" }}>{misses} missed</span>
        </div>
      )}
    </div>
  );
}

// ============================================================
// EXERCISE LOGGER — the heart of training
// ============================================================
function ExerciseLogger({ session, profile, exercise, supersetPartner, sessionName, themeCtx, onBack, onComplete }) {
  const { theme } = themeCtx;
  const [allLifts, setAllLifts] = useState({});
  const [sets, setSets] = useState([]);
  const [extraSets, setExtraSets] = useState(0);
  const [currentSet, setCurrentSet] = useState({ weight: 0, reps: 0, rir: 0, seconds: 0 });
  const [showSwap, setShowSwap] = useState(false);
  const [showNotes, setShowNotes] = useState(false);
  const [showHowTo, setShowHowTo] = useState(false);
  const [showCalibration, setShowCalibration] = useState(false);
  const [userNote, setUserNote] = useState("");
  const [ptNote, setPtNote] = useState("");
  const [swapResult, setSwapResult] = useState(null);
  const [swappedTo, setSwappedTo] = useState(null);
  const [activeRec, setActiveRec] = useState(null);
  const [showCelebration, setShowCelebration] = useState(null);
  const [warmupDone, setWarmupDone] = useState(false); // user marks warmup complete
  const [showRepRangeEditor, setShowRepRangeEditor] = useState(false);
  // One-time superset alternation intro (dismiss-only)
  const [showSupersetIntro, setShowSupersetIntro] = useState(false);
  // Dropset editor: when set, shows a modal to add drops to the indexed set
  const [dropsetFor, setDropsetFor] = useState(null); // { setIndex, draftDrops: [{weight, reps}] }
  // Rest timer: seconds left, only set when a set has just been logged (and in superset/general mode)
  // null = not active. > 0 = countdown. 0 = done (briefly shown before auto-clearing).
  const [restRemaining, setRestRemaining] = useState(null);
  const [restTotal, setRestTotal] = useState(60); // configurable per-session via tap

  // SUPERSET STATE — parallel state for the partner exercise
  // activeSide tracks which exercise is currently being logged (alternates each set):
  //   "A" = main exercise; "B" = partner. Defaults to whichever has fewer logged sets.
  const isSupersetMode = !!supersetPartner;
  const [bSets, setBSets] = useState([]);
  const [bCurrentSet, setBCurrentSet] = useState({ weight: 0, reps: 0, rir: 0, seconds: 0 });
  const [activeSide, setActiveSide] = useState("A");

  const totalSets = exercise.sets + extraSets;
  const repRange = parseRepRange(exercise.reps);
  const isTimed = isTimedExercise(exercise.name, exercise.reps);
  const isBodyweight = isBodyweightOnly(exercise.name);

  // Partner-side derivatives for superset mode. These mirror the A-side equivalents
  // but reference supersetPartner. Default to safe zero/empty when not in superset mode.
  const bTotalSets = supersetPartner ? supersetPartner.sets : 0;
  const bRepRange = supersetPartner ? parseRepRange(supersetPartner.reps) : { bot: 0, top: 0 };
  const bIsTimed = supersetPartner ? isTimedExercise(supersetPartner.name, supersetPartner.reps) : false;
  const bIsBodyweight = supersetPartner ? isBodyweightOnly(supersetPartner.name) : false;
  const bLastSession = supersetPartner ? (allLifts[supersetPartner.name]?.lastSession || []) : [];

  // Determine whether the superset is "done": both sides hit their totalSets
  const supersetDone = isSupersetMode && sets.length >= totalSets && bSets.length >= bTotalSets;
  // For superset mode, "done" is when both finished. Otherwise just the A side.
  const allDone = isSupersetMode ? supersetDone : sets.length >= totalSets;
  // Determine the next side to log given current state. Returns "A", "B", or null (done).
  const nextSide = (aLen, bLen) => {
    if (!isSupersetMode) return aLen >= totalSets ? null : "A";
    const aDone = aLen >= totalSets;
    const bDone = bLen >= bTotalSets;
    if (aDone && bDone) return null;
    if (aDone) return "B";
    if (bDone) return "A";
    // Alternate: whichever has fewer sets goes next; tie → switch from current side
    if (aLen < bLen) return "A";
    if (bLen < aLen) return "B";
    // Same length → switch (so user alternates rather than doubling up)
    return activeSide === "A" ? "B" : "A";
  };

  // Load lift history + notes on mount
  useEffect(() => {
    (async () => {
      const lifts = (await storage.get(userKey(session.id, "lifts"))) || {};
      setAllLifts(lifts);
      const exData = lifts[exercise.name];

      // Honour any accepted progression hints (weight/rep targets)
      const overrides = (await storage.get(userKey(session.id, "plan-overrides"))) || {};
      const weightHint = overrides.weightHints?.[exercise.name];
      const repHint = overrides.repHints?.[exercise.name];

      if (exData?.lastSession?.[0]) {
        const last = exData.lastSession[0];
        if (isTimed) {
          setCurrentSet({ weight: 0, reps: 0, rir: 0, seconds: last.seconds || 30 });
        } else {
          // Use accepted weight hint if present, else last session's weight
          const targetWeight = weightHint !== undefined ? weightHint : last.weight;
          const targetReps = repHint !== undefined ? repHint : (last.reps || repRange.top);
          setCurrentSet({ weight: targetWeight, reps: targetReps, rir: 0, seconds: 0 });
        }
      } else {
        // No history — fire calibration flow (unless timed/bodyweight which doesn't need it)
        if (isTimed) {
          setCurrentSet({ weight: 0, reps: 0, rir: 0, seconds: 30 });
        } else if (isBodyweight) {
          setCurrentSet({ weight: 0, reps: repRange.top, rir: 0, seconds: 0 });
        } else {
          setShowCalibration(true);
          setCurrentSet({ weight: 0, reps: repRange.top, rir: 0, seconds: 0 });
        }
      }

      const notes = (await storage.get(userKey(session.id, `notes:${exercise.name}`))) || {};
      setUserNote(notes.user || "");
      setPtNote(notes.pt || "");

      // SUPERSET: also load partner's last weight/reps to seed bCurrentSet
      if (supersetPartner) {
        const bData = lifts[supersetPartner.name];
        const bRepRange = parseRepRange(supersetPartner.reps);
        const bIsTimed = isTimedExercise(supersetPartner.name, supersetPartner.reps);
        const bIsBodyweight = isBodyweightOnly(supersetPartner.name);
        const bWeightHint = overrides.weightHints?.[supersetPartner.name];
        const bRepHint = overrides.repHints?.[supersetPartner.name];
        if (bData?.lastSession?.[0]) {
          const bLast = bData.lastSession[0];
          if (bIsTimed) {
            setBCurrentSet({ weight: 0, reps: 0, rir: 0, seconds: bLast.seconds || 30 });
          } else {
            const bw = bWeightHint !== undefined ? bWeightHint : bLast.weight;
            const br = bRepHint !== undefined ? bRepHint : (bLast.reps || bRepRange.top);
            setBCurrentSet({ weight: bw, reps: br, rir: 0, seconds: 0 });
          }
        } else if (bIsBodyweight) {
          setBCurrentSet({ weight: 0, reps: bRepRange.top, rir: 0, seconds: 0 });
        }
      }

      // First-time superset intro: show once, then mark dismissed in storage
      if (supersetPartner) {
        const seen = await storage.get(userKey(session.id, "superset-intro-seen"));
        if (!seen) setShowSupersetIntro(true);
      }
    })();
  }, [exercise.name, session.id]);

  // Rest-timer countdown: tick down 1/second while active
  useEffect(() => {
    if (restRemaining === null || restRemaining <= 0) return;
    const t = setTimeout(() => setRestRemaining(r => (r > 0 ? r - 1 : 0)), 1000);
    return () => clearTimeout(t);
  }, [restRemaining]);

  // Vibrate briefly when timer hits zero (if supported)
  useEffect(() => {
    if (restRemaining === 0 && navigator.vibrate) {
      try { navigator.vibrate([200, 100, 200]); } catch {}
    }
  }, [restRemaining]);

  const lastSession = allLifts[exercise.name]?.lastSession || [];
  const lastVolume = isTimed
    ? lastSession.reduce((s, set) => s + (set.seconds || 0), 0)
    : isBodyweight
    ? lastSession.reduce((s, set) => s + (set.reps || 0), 0)
    : lastSession.reduce((s, set) => s + set.weight * set.reps, 0);
  const currentVolume = isTimed
    ? sets.reduce((s, set) => s + (set.seconds || 0), 0)
    : isBodyweight
    ? sets.reduce((s, set) => s + (set.reps || 0), 0)
    : sets.reduce((s, set) => s + set.weight * set.reps, 0);

  // FORECAST: planned set list for the whole exercise, recomputed each render.
  // Completed sets show actual; remaining sets show projected (weight × reps)
  // based on current set's targets + small auto-adjustments for fatigue.
  //
  // Rule: if last set was tougher than expected (RIR 0 with reps below range),
  // remaining sets project at 90% weight. If last set crushed it (RIR 3+ at top
  // of range), remaining sets project at +2.5kg. Otherwise hold.
  const plannedSets = useMemo(() => {
    const list = [];
    // Start projection at currentSet's weight/reps
    let projWeight = currentSet.weight;
    let projReps = currentSet.reps;

    // Apply gentle drift based on the most recent completed set
    if (sets.length > 0 && !isTimed && !isBodyweight) {
      const lastDone = sets[sets.length - 1];
      const droppedBelowRange = lastDone.reps < repRange.bot && lastDone.rir <= 1;
      const crushedTop = lastDone.reps >= repRange.top && lastDone.rir >= 3;
      if (droppedBelowRange) {
        // Suggest dropping ~5-10% on remaining sets
        projWeight = Math.max(2.5, Math.round((lastDone.weight * 0.9) / 2.5) * 2.5);
        projReps = repRange.top;
      } else if (crushedTop) {
        // Could add a bit more — but stay conservative within session
        projWeight = lastDone.weight; // hold weight, the +2.5kg signal is for next session
        projReps = Math.min(repRange.top, lastDone.reps);
      } else {
        projWeight = lastDone.weight;
        projReps = lastDone.reps;
      }
    }

    for (let i = 0; i < totalSets; i++) {
      if (i < sets.length) {
        list.push({ ...sets[i], status: "done" });
      } else if (i === sets.length) {
        // Current set in progress — use live currentSet values
        list.push({
          weight: currentSet.weight,
          reps: currentSet.reps,
          rir: currentSet.rir,
          seconds: currentSet.seconds,
          status: "active",
        });
      } else {
        // Future set — projected
        list.push({
          weight: isBodyweight ? 0 : projWeight,
          reps: projReps,
          rir: null,
          seconds: isTimed ? (lastSession[i]?.seconds || 30) : 0,
          status: "planned",
        });
      }
    }

    // If a dropset is suggested, attach a projected drop to the FINAL set
    if (exercise.dropsetSuggested && totalSets > 0 && !isTimed && !isBodyweight) {
      const finalIdx = totalSets - 1;
      const finalEntry = list[finalIdx];
      // Don't override if user already set drops on the actual set
      if (!finalEntry.drops || finalEntry.drops.length === 0) {
        const dropW = Math.max(2.5, Math.round((finalEntry.weight * 0.7) / 2.5) * 2.5);
        const dropReps = Math.max(1, finalEntry.reps - 2);
        finalEntry.suggestedDrops = [{ weight: dropW, reps: `${dropReps}+`, projected: true }];
      }
    }

    return list;
  }, [sets, currentSet, totalSets, repRange, isTimed, isBodyweight, exercise.dropsetSuggested, lastSession]);

  // Partner-side forecast — mirrors plannedSets logic, only built when in superset mode
  const bPlannedSets = useMemo(() => {
    if (!isSupersetMode) return [];
    const list = [];
    let projWeight = bCurrentSet.weight;
    let projReps = bCurrentSet.reps;

    if (bSets.length > 0 && !bIsTimed && !bIsBodyweight) {
      const lastDone = bSets[bSets.length - 1];
      const droppedBelowRange = lastDone.reps < bRepRange.bot && lastDone.rir <= 1;
      const crushedTop = lastDone.reps >= bRepRange.top && lastDone.rir >= 3;
      if (droppedBelowRange) {
        projWeight = Math.max(2.5, Math.round((lastDone.weight * 0.9) / 2.5) * 2.5);
        projReps = bRepRange.top;
      } else if (crushedTop) {
        projWeight = lastDone.weight;
        projReps = Math.min(bRepRange.top, lastDone.reps);
      } else {
        projWeight = lastDone.weight;
        projReps = lastDone.reps;
      }
    }

    for (let i = 0; i < bTotalSets; i++) {
      if (i < bSets.length) {
        list.push({ ...bSets[i], status: "done" });
      } else if (i === bSets.length) {
        list.push({
          weight: bCurrentSet.weight,
          reps: bCurrentSet.reps,
          rir: bCurrentSet.rir,
          seconds: bCurrentSet.seconds,
          status: "active",
        });
      } else {
        list.push({
          weight: bIsBodyweight ? 0 : projWeight,
          reps: projReps,
          rir: null,
          seconds: bIsTimed ? (bLastSession[i]?.seconds || 30) : 0,
          status: "planned",
        });
      }
    }
    return list;
  }, [isSupersetMode, bSets, bCurrentSet, bTotalSets, bRepRange, bIsTimed, bIsBodyweight, bLastSession]);

  const volumeUnit = isTimed ? "sec" : isBodyweight ? "reps" : "kg";

  const logSet = () => {
    // Branch: if superset mode AND active side is B, log to B-side
    if (isSupersetMode && activeSide === "B") {
      // Validate B-side
      if (bIsTimed) {
        if (bCurrentSet.seconds === 0) return;
      } else if (bIsBodyweight) {
        if (bCurrentSet.reps === 0) return;
      } else {
        if (bCurrentSet.weight === 0 && bCurrentSet.reps === 0) return;
      }
      const newBSet = { ...bCurrentSet };
      const newBSets = [...bSets, newBSet];
      setBSets(newBSets);

      // Decide what comes next
      const next = nextSide(sets.length, newBSets.length);
      if (next === null) {
        setActiveRec(null);
        setRestRemaining(null);
        return;
      }
      // Seed next active set's defaults
      if (next === "A") {
        setActiveSide("A");
        // Switching sides — start rest timer (full superset rest between rounds)
        setRestRemaining(restTotal);
        // Set up A-side currentSet rec (based on A's most recent done set if any)
        if (!isTimed && !isBodyweight) {
          const aLastDone = sets[sets.length - 1];
          if (aLastDone) {
            const rec = getSetRecommendation(aLastDone, repRange);
            setActiveRec(rec);
            setCurrentSet({ weight: rec.weight, reps: rec.reps, rir: rec.rir, seconds: 0 });
          }
        }
      } else {
        // Stay on B for another set — full rest (A is done, B is finishing alone)
        setActiveSide("B");
        setRestRemaining(restTotal);
        if (!bIsTimed && !bIsBodyweight) {
          const rec = getSetRecommendation(newBSet, bRepRange);
          setBCurrentSet({ weight: rec.weight, reps: rec.reps, rir: rec.rir, seconds: 0 });
        } else if (bIsTimed) {
          setBCurrentSet({ weight: 0, reps: 0, rir: 0, seconds: newBSet.seconds });
        } else {
          setBCurrentSet({ weight: 0, reps: newBSet.reps, rir: 0, seconds: 0 });
        }
      }
      return;
    }

    // A-side path (default for non-superset and active=A)
    if (isTimed) {
      if (currentSet.seconds === 0) return;
    } else if (isBodyweight) {
      if (currentSet.reps === 0) return;
    } else {
      if (currentSet.weight === 0 && currentSet.reps === 0) return;
    }
    const newSet = { ...currentSet };
    const newSets = [...sets, newSet];
    setSets(newSets);

    // Decide next side / done
    if (isSupersetMode) {
      const next = nextSide(newSets.length, bSets.length);
      if (next === null) {
        setActiveRec(null);
        setRestRemaining(null);
        return;
      }
      if (next === "B") {
        setActiveSide("B");
        // Switching immediately to B — no rest between A and B in a superset round
        setRestRemaining(null);
        // Seed B-side rec based on B's previous done set if any
        if (!bIsTimed && !bIsBodyweight) {
          const bLastDone = bSets[bSets.length - 1];
          if (bLastDone) {
            const rec = getSetRecommendation(bLastDone, bRepRange);
            setActiveRec(rec);
            setBCurrentSet({ weight: rec.weight, reps: rec.reps, rir: rec.rir, seconds: 0 });
          }
        }
        return;
      }
      // Else: stay on A for another set — give rest before doing another A
      setActiveSide("A");
      setRestRemaining(restTotal);
    } else if (newSets.length >= totalSets) {
      setActiveRec(null);
      setRestRemaining(null);
      return;
    } else {
      // Non-superset mode, more sets to do — start rest timer
      setRestRemaining(restTotal);
    }

    // Seed next A-side currentSet
    if (!isTimed && !isBodyweight) {
      const rec = getSetRecommendation(newSet, repRange);
      setActiveRec(rec);
      setCurrentSet({ weight: rec.weight, reps: rec.reps, rir: rec.rir, seconds: 0 });
    } else if (isTimed) {
      const lastSet = lastSession[newSets.length];
      const target = lastSet?.seconds || newSet.seconds;
      setCurrentSet({ weight: 0, reps: 0, rir: 0, seconds: target });
    } else {
      setCurrentSet({ weight: 0, reps: newSet.reps, rir: 0, seconds: 0 });
    }
  };

  const acceptRec = () => {
    setActiveRec(null);
  };

  const finishExercise = async (finalSets) => {
    const lifts = (await storage.get(userKey(session.id, "lifts"))) || {};
    const today = new Date().toISOString().split("T")[0];

    // Always write A-side
    const existingA = lifts[exercise.name] || { history: [] };
    lifts[exercise.name] = {
      lastSession: finalSets,
      lastDate: today,
      history: [...(existingA.history || []), { date: today, sets: finalSets }].slice(-20),
    };

    // In superset mode, also write B-side
    if (isSupersetMode && supersetPartner && bSets.length > 0) {
      const existingB = lifts[supersetPartner.name] || { history: [] };
      lifts[supersetPartner.name] = {
        lastSession: bSets,
        lastDate: today,
        history: [...(existingB.history || []), { date: today, sets: bSets }].slice(-20),
      };
    }

    await storage.set(userKey(session.id, "lifts"), lifts);

    // Record intensification history so future plan generations can rotate.
    // Only record what was actually engine-suggested (and where the user followed through).
    const prefs = (await storage.get(userKey(session.id, "exercise-prefs"))) || {};
    const intensificationHistory = prefs.intensificationHistory || [];
    const newEntries = [];
    // Superset: log if A was an engine pair AND we logged at least 1 set on both sides
    if (exercise.supersetSource === "engine" && isSupersetMode && finalSets.length > 0 && bSets.length > 0) {
      newEntries.push({ date: today, type: "superset", names: [exercise.name, supersetPartner.name] });
    }
    // Dropset: log if engine-suggested AND user actually added drops on at least one set
    if (exercise.dropsetSuggested && finalSets.some(s => s.drops?.length > 0)) {
      newEntries.push({ date: today, type: "dropset", names: [exercise.name] });
    }
    if (newEntries.length > 0) {
      // Keep last 28 days only
      const cutoff = new Date(today); cutoff.setDate(cutoff.getDate() - 28);
      const trimmed = intensificationHistory.filter(e => new Date(e.date) >= cutoff);
      await storage.set(userKey(session.id, "exercise-prefs"), {
        ...prefs,
        intensificationHistory: [...trimmed, ...newEntries],
      });
    }

    onComplete();
  };

  // Add an extra "push set" with suggested values, kicking the user back into the active set logger
  const addPushSet = (suggested) => {
    setExtraSets(extraSets + 1);
    setCurrentSet({ weight: suggested.weight, reps: suggested.reps, rir: 1 });
    setActiveRec(null);
  };

  // Show celebration screen, then commit the lift after user dismisses
  const finishWithCelebration = (finalSets, beat) => {
    const finalVolume = isTimed
      ? finalSets.reduce((s, set) => s + (set.seconds || 0), 0)
      : isBodyweight
      ? finalSets.reduce((s, set) => s + (set.reps || 0), 0)
      : finalSets.reduce((s, set) => s + set.weight * set.reps, 0);
    const u = volumeUnit;
    const diff = finalVolume - lastVolume;
    let tone, headline, sub;
    if (lastVolume === 0) {
      tone = "first";
      headline = "🎬 Baseline locked in";
      sub = `${Math.round(finalVolume).toLocaleString()} ${u} banked. Now you've got something to beat next week.`;
    } else if (beat || diff > 0) {
      tone = "win";
      const pct = Math.round((diff / lastVolume) * 100);
      const emojis = ["🏆", "🔥", "💪", "🚀", "⚡"];
      const headlines = [
        "New PR vibes",
        "You crushed it",
        "Up only",
        "Better than last week",
        "Progress made",
      ];
      const idx = finalSets.length % headlines.length;
      headline = `${emojis[idx]} ${headlines[idx]}`;
      sub = `${Math.round(finalVolume).toLocaleString()} ${u} total — beat last week by ${Math.round(diff).toLocaleString()} ${u} (${pct}%).`;
    } else if (Math.abs(diff) < lastVolume * 0.02) {
      tone = "match";
      headline = "🤝 Held the line";
      sub = `${Math.round(finalVolume).toLocaleString()} ${u} — matched last week. Consistency is its own win.`;
    } else {
      tone = "miss";
      const messages = [
        "Off day. Sleep, stress, food — it all matters. Show up next week.",
        "Couldn't beat it today. The weight will be there next session.",
        "Building base. Not every session is a PR.",
        "Logged the work. That's the win — turn up consistently and the numbers follow.",
      ];
      const idx = finalSets.length % messages.length;
      headline = "Logged";
      sub = `${Math.round(finalVolume).toLocaleString()} ${u} — ${Math.round(Math.abs(diff)).toLocaleString()} ${u} below last week. ${messages[idx]}`;
    }
    setShowCelebration({ tone, headline, sub, finalSets });
  };

  const dismissCelebration = async () => {
    if (showCelebration?.finalSets) await finishExercise(showCelebration.finalSets);
    setShowCelebration(null);
  };

  const undoSet = () => {
    if (sets.length === 0) return;
    const newSets = sets.slice(0, -1);
    setSets(newSets);
    setCurrentSet(sets[sets.length - 1]);
    setActiveRec(null);
  };

  const saveNotes = async () => {
    // Re-read existing to avoid clobbering changes from other roles
    const existing = (await storage.get(userKey(session.id, `notes:${exercise.name}`))) || {};
    const isPT = session.role === "PT";
    const next = isPT
      ? { user: existing.user || userNote, pt: ptNote }
      : { user: userNote, pt: existing.pt || ptNote };
    await storage.set(userKey(session.id, `notes:${exercise.name}`), next);
    setShowNotes(false);
  };

  // Volume comparison vs last week
  const projectedVolume = sets.length < totalSets
    ? currentVolume + (currentSet.weight * currentSet.reps)
    : currentVolume;
  const beatLastWeek = currentVolume > lastVolume;
  const onTrackToBeat = projectedVolume > lastVolume;

  return (
    <div className={`min-h-screen ${theme.bg} pb-32`}>
      <div className="max-w-md mx-auto">
        <div className="px-5 pt-10 pb-6 text-white relative overflow-hidden" style={{ background: `linear-gradient(135deg, ${theme.headerStart}, ${theme.headerEnd})` }}>
          <img src={HERO_SQUAT_B64} alt="" className="absolute inset-0 w-full h-full object-cover" style={{ opacity: 0.25, mixBlendMode: "luminosity" }} />
          <div className="relative">
            <button onClick={onBack} className="text-blue-100 text-sm flex items-center gap-1 mb-3">← {sessionName}</button>
            {swappedTo ? (
              <>
                <div className="text-blue-200 text-xs line-through mb-1">{exercise.name}</div>
                <h1 className="text-2xl font-bold">{swappedTo}</h1>
              </>
            ) : (
              <h1 className="text-2xl font-bold">{exercise.name}</h1>
            )}
            <p className="text-blue-100 text-sm mt-1">{totalSets} sets × {exercise.reps} reps</p>
            {exercise.supersetWith && (
              <div className="mt-2 inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full" style={{ backgroundColor: `${ORANGE}33` }}>
                <span className="text-[10px] font-bold tracking-wider" style={{ color: ORANGE }}>SUPERSET</span>
                <span className="text-[11px] text-blue-100">
                  {exercise.supersetRole === "B" ? `after ${exercise.supersetWith}` : `→ then ${exercise.supersetWith}`}
                </span>
              </div>
            )}
          </div>
        </div>

        {/* PT note pinned at top if exists */}
        {ptNote && (
          <div className="px-4 mt-4">
            <div className="rounded-xl p-3 border" style={{ backgroundColor: "#f5f3ff", borderColor: "#ddd6fe" }}>
              <div className="text-[10px] font-bold uppercase tracking-wide mb-1" style={{ color: "#7c3aed" }}>PT note</div>
              <div className="text-sm" style={{ color: "#5b21b6" }}>{ptNote}</div>
            </div>
          </div>
        )}

        {/* Action buttons */}
        <div className="px-4 mt-4 grid grid-cols-2 gap-2">
          <button onClick={() => setShowHowTo(true)} className="h-11 rounded-xl text-xs font-semibold text-white" style={{ backgroundColor: NAVY }}>
            📚 How to do this
          </button>
          <button onClick={() => setShowNotes(true)} className={`h-11 ${theme.surface} ${theme.surfaceText} rounded-xl text-xs font-semibold`}>
            Notes{userNote || ptNote ? " ✓" : ""}
          </button>
        </div>
        <div className="px-4 mt-2 grid grid-cols-3 gap-2">
          <button onClick={() => setShowSwap(true)} className="h-11 rounded-xl text-xs font-semibold border" style={{ backgroundColor: `${ORANGE}15`, color: ORANGE, borderColor: `${ORANGE}55` }}>
            Unavailable
          </button>
          <button onClick={() => setShowRepRangeEditor(true)} className={`h-11 ${theme.surface} ${theme.surfaceText} rounded-xl text-xs font-semibold flex items-center justify-center`}>
            Rep range
            {exercise.repsOverridden && <span className="ml-1 w-1.5 h-1.5 rounded-full" style={{ backgroundColor: ORANGE }} />}
          </button>
          <button onClick={() => setExtraSets(extraSets + 1)} className={`h-11 ${theme.surface} ${theme.surfaceText} rounded-xl text-xs font-semibold`}>
            + Add set
          </button>
        </div>

        {/* Warmup card — only shown if the exercise's library entry suggests warmup sets.
            Suggests warmup weights as % of the working weight (50% / 70% / 85%).
            Bodyweight and timed exercises skip warmups (no weight to ramp). */}
        {(() => {
          const libEntry = EXERCISE_LIBRARY[swappedTo || exercise.name];
          const suggested = libEntry?.warmupSets ?? 0;
          if (suggested === 0 || isBodyweight || isTimed) return null;
          const workingW = currentSet.weight || 0;
          if (workingW <= 0) return null;
          // Round to nearest 2.5kg for barbell, 1kg for others
          const isBarbell = libEntry?.equipment === "Barbell";
          const roundTo = (w) => {
            const step = isBarbell ? 2.5 : 1;
            return Math.max(step, Math.round(w / step) * step);
          };
          const ramps = suggested >= 3
            ? [{ pct: 0.40, reps: 8 }, { pct: 0.60, reps: 5 }, { pct: 0.80, reps: 3 }]
            : suggested === 2
              ? [{ pct: 0.50, reps: 8 }, { pct: 0.75, reps: 5 }]
              : [{ pct: 0.60, reps: 8 }];
          return (
            <div className="px-4 mt-3">
              <div className={`${theme.card} rounded-2xl border ${theme.border} p-3`}
                style={{ borderLeft: `3px solid ${warmupDone ? "#10b981" : "#f59e0b"}` }}>
                <div className="flex items-center justify-between mb-2">
                  <div className="flex items-center gap-2">
                    <span className="text-base">🔥</span>
                    <span className={`text-xs font-bold uppercase tracking-wide ${theme.text}`}>Warmup</span>
                    <span className="text-[9px] px-1.5 py-0.5 rounded font-semibold"
                      style={{ backgroundColor: warmupDone ? "#10b98120" : "#f59e0b20", color: warmupDone ? "#10b981" : "#f59e0b" }}>
                      {warmupDone ? "DONE" : `${suggested} ${suggested === 1 ? "set" : "sets"}`}
                    </span>
                  </div>
                  <button onClick={() => setWarmupDone(!warmupDone)}
                    className="text-[10px] underline" style={{ color: ORANGE }}>
                    {warmupDone ? "Reset" : "Mark done"}
                  </button>
                </div>
                {!warmupDone && (
                  <div className="space-y-1">
                    {ramps.map((r, i) => (
                      <div key={i} className={`flex items-center justify-between p-1.5 ${theme.surface} rounded text-[11px]`}>
                        <span className={`font-semibold ${theme.text}`}>Set {i + 1}</span>
                        <span className={theme.text}>{roundTo(workingW * r.pct)} kg × {r.reps} reps</span>
                        <span className={theme.textMuted}>~{Math.round(r.pct * 100)}%</span>
                      </div>
                    ))}
                    <p className={`text-[10px] ${theme.textMuted} mt-1 italic`}>
                      Suggestions only. Rest 30-60s between warmup sets. Working sets stay at {workingW} kg.
                    </p>
                  </div>
                )}
              </div>
            </div>
          );
        })()}

        {/* Suggested dropset banner (engine-suggested for this exercise).
            Tells the user there's a planned dropset on the final set, with a Skip button. */}
        {exercise.dropsetSuggested && (
          <div className="px-4 mt-3">
            <div className={`${theme.card} rounded-2xl border ${theme.border} p-3`}
              style={{ borderLeft: "3px solid #15803d" }}>
              <div className="flex items-center justify-between mb-1">
                <div className="flex items-center gap-2">
                  <span className="text-base">⬇️</span>
                  <span className={`text-xs font-bold uppercase tracking-wide ${theme.text}`}>Suggested dropset</span>
                  <span className="text-[9px] px-1.5 py-0.5 rounded font-semibold"
                    style={{ backgroundColor: "#15803d20", color: "#15803d" }}>
                    LAST SET
                  </span>
                </div>
              </div>
              <p className={`text-[11px] ${theme.textMuted} leading-snug mb-2`}>
                {exercise.dropsetSuggested.reason}. After your last working set, drop to ~70% weight and rep out. Tap "+ Drop" on your final set to log it.
              </p>
              <p className={`text-[10px] ${theme.textMuted} italic`}>
                Don't want to today? Tap the "+ Drop" button to skip — the suggestion is just guidance.
              </p>
            </div>
          </div>
        )}

        {/* Volume comparison */}
        <div className="px-4 mt-4">
          <div className={`${theme.card} rounded-2xl border-2 ${theme.border} p-4`}>
            <div className="grid grid-cols-2 gap-3 mb-3">
              <div className="text-center">
                <div className={`text-[10px] uppercase tracking-wide ${theme.textMuted} font-bold`}>Last week</div>
                <div className={`text-2xl font-bold ${theme.text}`}>{Math.round(lastVolume).toLocaleString()}</div>
                <div className={`text-[10px] ${theme.textMuted}`}>{volumeUnit} total</div>
              </div>
              <div className="text-center">
                <div className="text-[10px] uppercase tracking-wide font-bold" style={{ color: ORANGE }}>This week</div>
                <div className="text-2xl font-bold" style={{ color: ORANGE }}>{Math.round(currentVolume).toLocaleString()}</div>
                <div className={`text-[10px] ${theme.textMuted}`}>{volumeUnit} so far</div>
              </div>
            </div>
            {lastVolume > 0 && (
              <div className="text-center">
                <div className="h-2 bg-slate-200 rounded-full overflow-hidden mb-2">
                  <div className="h-full transition-all" style={{ width: `${Math.min(100, (currentVolume / lastVolume) * 100)}%`, backgroundColor: beatLastWeek ? "#10b981" : ORANGE }} />
                </div>
                <p className="text-xs font-semibold" style={{ color: beatLastWeek ? "#10b981" : onTrackToBeat ? ORANGE : theme.textMuted.replace("text-slate-", "") }}>
                  {beatLastWeek ? `🏆 Beating last week by ${Math.round(currentVolume - lastVolume)}${volumeUnit}` :
                   onTrackToBeat ? `On track — projected ${Math.round(projectedVolume).toLocaleString()}${volumeUnit}` :
                   `Need ${Math.round(lastVolume - currentVolume)}${volumeUnit} more to beat last week`}
                </p>
              </div>
            )}
            {lastVolume === 0 && <p className={`text-xs text-center ${theme.textMuted}`}>No history yet — your first session sets the baseline</p>}
          </div>
        </div>

        {/* Completed sets — only in non-superset mode (forecast handles superset display) */}
        {!isSupersetMode && sets.length > 0 && (
          <div className="px-4 mt-4">
            <h3 className={`text-xs font-bold uppercase tracking-wide ${theme.textMuted} mb-2`}>Completed sets</h3>
            <div className="space-y-1.5">
              {sets.map((s, i) => (
                <div key={i} className={`rounded-lg border ${theme.border}`} style={{ backgroundColor: "#dcfce7" }}>
                  <div className="flex items-center gap-3 p-3">
                    <div className="w-8 h-8 rounded-full bg-emerald-500 text-white flex items-center justify-center font-bold text-xs">{i + 1}</div>
                    <div className="flex-1">
                      <div className="font-bold text-emerald-900 flex items-center gap-1.5">
                        {isTimed ? `${s.seconds}s hold` : isBodyweight ? `${s.reps} reps` : `${s.weight}kg × ${s.reps} reps`}
                        {s.drops?.length > 0 && (
                          <span className="text-[9px] font-bold px-1.5 py-0.5 rounded" style={{ backgroundColor: "#15803d", color: "white" }}>
                            +{s.drops.length} DROP{s.drops.length > 1 ? "S" : ""}
                          </span>
                        )}
                      </div>
                      <div className="text-[11px] text-emerald-700">
                        {(() => {
                          const baseVol = isTimed ? 0 : isBodyweight ? s.reps : s.weight * s.reps;
                          const dropVol = (s.drops || []).reduce((sum, d) => sum + (d.weight * d.reps), 0);
                          const totalVol = baseVol + dropVol;
                          return isTimed
                            ? `${s.seconds}s`
                            : isBodyweight
                              ? `${s.reps} reps`
                              : `${totalVol}kg vol${dropVol > 0 ? ` (+${dropVol} from drops)` : ""}`;
                        })()}
                        {!isTimed && ` · RIR ${s.rir === 3 ? "2+" : s.rir}`}
                      </div>
                    </div>
                    {!isTimed && !isBodyweight && (
                      <button onClick={() => setDropsetFor({ setIndex: i, draftDrops: s.drops?.length ? [...s.drops] : [{ weight: Math.max(2.5, Math.round((s.weight * 0.7) / 2.5) * 2.5), reps: Math.max(1, s.reps - 2) }] })}
                        className="text-[10px] font-semibold px-2 py-1 rounded" style={{ backgroundColor: "#15803d20", color: "#15803d" }}>
                        {s.drops?.length > 0 ? "Edit drop" : "+ Drop"}
                      </button>
                    )}
                    {i === sets.length - 1 && <button onClick={undoSet} className="text-emerald-700 text-xs font-semibold">Undo</button>}
                  </div>
                  {/* Drop set chain rendered inline below the main set */}
                  {s.drops?.length > 0 && (
                    <div className="px-3 pb-2 -mt-1 space-y-1">
                      {s.drops.map((d, di) => (
                        <div key={di} className="flex items-center gap-2 text-[11px] pl-10">
                          <span className="text-emerald-700">↳</span>
                          <span className="font-semibold text-emerald-900">Drop {di + 1}</span>
                          <span className="text-emerald-800">{d.weight}kg × {d.reps} reps</span>
                          <span className="text-emerald-700 text-[10px]">({d.weight * d.reps}kg)</span>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Inline recommendation banner — shows after each set */}
        {activeRec && sets.length < totalSets && (
          <div className="px-4 mt-4">
            <div className="rounded-2xl p-4 border-2" style={{
              backgroundColor: activeRec.tone === "level_up" ? "#dcfce7" : activeRec.tone === "drop" ? "#fef2f2" : activeRec.tone === "push" ? `${ORANGE}15` : "#f1f5f9",
              borderColor: activeRec.tone === "level_up" ? "#86efac" : activeRec.tone === "drop" ? "#fca5a5" : activeRec.tone === "push" ? `${ORANGE}55` : "#cbd5e1",
            }}>
              <div className="text-xs font-bold uppercase tracking-wide mb-2" style={{
                color: activeRec.tone === "level_up" ? "#15803d" : activeRec.tone === "drop" ? "#b91c1c" : activeRec.tone === "push" ? ORANGE : "#475569",
              }}>
                {activeRec.tone === "level_up" ? "Level up" : activeRec.tone === "drop" ? "Drop the weight" : activeRec.tone === "push" ? "Push for more" : "✓ Stay on it"}
              </div>
              <p className="text-sm font-medium" style={{
                color: activeRec.tone === "level_up" ? "#14532d" : activeRec.tone === "drop" ? "#7f1d1d" : activeRec.tone === "push" ? "#92400e" : "#1e293b",
              }}>
                {activeRec.message}
              </p>
              <div className="mt-3 flex items-center gap-2">
                <button onClick={acceptRec} className="flex-1 h-11 text-white rounded-lg font-bold text-sm" style={{
                  backgroundColor: activeRec.tone === "level_up" ? "#10b981" : activeRec.tone === "drop" ? "#ef4444" : ORANGE,
                }}>
                  {activeRec.action} →
                </button>
                <button onClick={() => setActiveRec(null)} className="h-11 px-3 rounded-lg font-semibold text-xs" style={{ backgroundColor: "white", color: "#475569", border: "1px solid #cbd5e1" }}>
                  Override
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Forecast — full set roadmap visible at all times.
            In superset mode, shows A side here; B side renders in its own card below. */}
        {plannedSets.length > 0 && (
          <div className="px-4 mt-4">
            <div className={`${theme.card} rounded-2xl border ${theme.border} p-3`} style={isSupersetMode ? { borderLeft: `3px solid ${ORANGE}` } : {}}>
              <div className="flex items-center justify-between mb-2">
                <h4 className={`text-[10px] font-bold uppercase tracking-wider ${theme.textMuted} flex items-center gap-1.5`}>
                  {isSupersetMode && (
                    <span className="text-[9px] font-bold tracking-wider px-1.5 py-0.5 rounded" style={{ backgroundColor: ORANGE, color: "white" }}>A</span>
                  )}
                  <span>{isSupersetMode ? (swappedTo || exercise.name) : "Planned sets"}</span>
                  {sets.length > 0 && <span className={theme.textMuted}>· {sets.length}/{totalSets} done</span>}
                </h4>
                {!isSupersetMode && <span className={`text-[9px] ${theme.textMuted} italic`}>updates as you log</span>}
              </div>
              <div className="space-y-1">
                {plannedSets.map((p, i) => {
                  const isDone = p.status === "done";
                  const isActive = p.status === "active";
                  const isPlanned = p.status === "planned";
                  return (
                    <div key={i}>
                      <div className="flex items-center gap-2 p-2 rounded-lg" style={{
                        backgroundColor: isDone ? "#dcfce7" : isActive ? `${ORANGE}15` : (theme.bg.includes("950") ? "#1e293b" : "#f8fafc"),
                        border: isActive ? `1px solid ${ORANGE}66` : "1px solid transparent",
                      }}>
                        <div className="w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold flex-shrink-0"
                          style={{
                            backgroundColor: isDone ? "#10b981" : isActive ? ORANGE : (theme.bg.includes("950") ? "#334155" : "#cbd5e1"),
                            color: "white",
                          }}>
                          {isDone ? "✓" : i + 1}
                        </div>
                        <div className="flex-1 text-[12px]" style={{ color: isDone ? "#15803d" : isActive ? ORANGE : (theme.bg.includes("950") ? "#94a3b8" : "#64748b") }}>
                          {isTimed ? (
                            <span className={isDone || isActive ? "font-semibold" : ""}>{p.seconds}s</span>
                          ) : isBodyweight ? (
                            <span className={isDone || isActive ? "font-semibold" : ""}>{p.reps} reps</span>
                          ) : (
                            <span className={isDone || isActive ? "font-semibold" : ""}>{p.weight}kg × {p.reps} reps</span>
                          )}
                          {isDone && !isTimed && (
                            <span className="ml-2 text-[10px]" style={{ color: "#15803d99" }}>RIR {p.rir === 3 ? "2+" : p.rir}</span>
                          )}
                          {isPlanned && (
                            <span className={`ml-2 text-[9px] italic ${theme.textMuted}`}>projected</span>
                          )}
                        </div>
                      </div>
                      {/* Dropset display — actual logged drops or suggested */}
                      {p.drops?.length > 0 && (
                        <div className="ml-8 mt-0.5 space-y-0.5">
                          {p.drops.map((d, di) => (
                            <div key={di} className="flex items-center gap-1.5 text-[10px]" style={{ color: "#15803d" }}>
                              <span>↳</span>
                              <span className="font-semibold">Drop {di + 1}:</span>
                              <span>{d.weight}kg × {d.reps} reps</span>
                            </div>
                          ))}
                        </div>
                      )}
                      {p.suggestedDrops && (
                        <div className="ml-8 mt-0.5 space-y-0.5">
                          {p.suggestedDrops.map((d, di) => (
                            <div key={di} className="flex items-center gap-1.5 text-[10px]" style={{ color: "#15803d99" }}>
                              <span>↳</span>
                              <span className="font-semibold">Suggested drop:</span>
                              <span>{d.weight}kg × {d.reps} reps</span>
                              <span className="italic">(planned)</span>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
              {/* Volume preview at the bottom */}
              {!isTimed && !isBodyweight && (
                <div className={`mt-2 pt-2 border-t ${theme.border} flex items-center justify-between text-[10px]`}>
                  <span className={theme.textMuted}>Projected total</span>
                  <span className={`font-semibold ${theme.text}`}>
                    {Math.round(plannedSets.reduce((sum, p) => {
                      const base = (p.weight || 0) * (p.reps || 0);
                      const dropV = (p.drops || []).reduce((s, d) => s + d.weight * d.reps, 0);
                      // For suggestedDrops, parse reps which may be like "6+"
                      const sugDropV = (p.suggestedDrops || []).reduce((s, d) => {
                        const r = typeof d.reps === "string" ? parseInt(d.reps, 10) || 0 : d.reps;
                        return s + d.weight * r;
                      }, 0);
                      return sum + base + dropV + sugDropV;
                    }, 0)).toLocaleString()} kg
                  </span>
                </div>
              )}
            </div>
          </div>
        )}

        {/* B-side forecast card — only in superset mode, mirrors A but with B label */}
        {isSupersetMode && bPlannedSets.length > 0 && (
          <div className="px-4 mt-2">
            <div className={`${theme.card} rounded-2xl border ${theme.border} p-3`} style={{ borderLeft: `3px solid ${ORANGE}` }}>
              <div className="flex items-center justify-between mb-2">
                <h4 className={`text-[10px] font-bold uppercase tracking-wider ${theme.textMuted} flex items-center gap-1.5`}>
                  <span className="text-[9px] font-bold tracking-wider px-1.5 py-0.5 rounded" style={{ backgroundColor: ORANGE, color: "white" }}>B</span>
                  <span>{supersetPartner.name}</span>
                  {bSets.length > 0 && <span className={theme.textMuted}>· {bSets.length}/{bTotalSets} done</span>}
                </h4>
              </div>
              <div className="space-y-1">
                {bPlannedSets.map((p, i) => {
                  const isDone = p.status === "done";
                  const isActive = p.status === "active" && activeSide === "B";
                  const isPlanned = p.status === "planned" || (p.status === "active" && activeSide !== "B");
                  return (
                    <div key={i} className="flex items-center gap-2 p-2 rounded-lg" style={{
                      backgroundColor: isDone ? "#dcfce7" : isActive ? `${ORANGE}15` : (theme.bg.includes("950") ? "#1e293b" : "#f8fafc"),
                      border: isActive ? `1px solid ${ORANGE}66` : "1px solid transparent",
                    }}>
                      <div className="w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold flex-shrink-0"
                        style={{
                          backgroundColor: isDone ? "#10b981" : isActive ? ORANGE : (theme.bg.includes("950") ? "#334155" : "#cbd5e1"),
                          color: "white",
                        }}>
                        {isDone ? "✓" : i + 1}
                      </div>
                      <div className="flex-1 text-[12px]" style={{ color: isDone ? "#15803d" : isActive ? ORANGE : (theme.bg.includes("950") ? "#94a3b8" : "#64748b") }}>
                        {bIsTimed ? (
                          <span className={isDone || isActive ? "font-semibold" : ""}>{p.seconds}s</span>
                        ) : bIsBodyweight ? (
                          <span className={isDone || isActive ? "font-semibold" : ""}>{p.reps} reps</span>
                        ) : (
                          <span className={isDone || isActive ? "font-semibold" : ""}>{p.weight}kg × {p.reps} reps</span>
                        )}
                        {isDone && !bIsTimed && (
                          <span className="ml-2 text-[10px]" style={{ color: "#15803d99" }}>RIR {p.rir === 3 ? "2+" : p.rir}</span>
                        )}
                        {isPlanned && (
                          <span className={`ml-2 text-[9px] italic ${theme.textMuted}`}>projected</span>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
              {!bIsTimed && !bIsBodyweight && (
                <div className={`mt-2 pt-2 border-t ${theme.border} flex items-center justify-between text-[10px]`}>
                  <span className={theme.textMuted}>Projected total</span>
                  <span className={`font-semibold ${theme.text}`}>
                    {Math.round(bPlannedSets.reduce((sum, p) => sum + (p.weight || 0) * (p.reps || 0), 0)).toLocaleString()} kg
                  </span>
                </div>
              )}
            </div>
          </div>
        )}

        {/* Rest timer — only when one's active. Compact banner above the logger. */}
        {restRemaining !== null && (
          <div className="px-4 mt-3">
            <div className={`${theme.card} rounded-xl border-2 p-3 flex items-center gap-3`}
              style={{
                borderColor: restRemaining === 0 ? "#10b981" : restRemaining < 10 ? STATUS_STATIC : `${NAVY}55`,
                backgroundColor: restRemaining === 0 ? "#10b98115" : restRemaining < 10 ? `${STATUS_STATIC}10` : "",
              }}>
              <div className="text-2xl font-bold flex-shrink-0" style={{
                color: restRemaining === 0 ? "#10b981" : restRemaining < 10 ? STATUS_STATIC : (theme.text === "text-slate-100" ? "#f1f5f9" : "#0f172a"),
              }}>
                {restRemaining === 0 ? "✓" : `${Math.floor(restRemaining / 60)}:${String(restRemaining % 60).padStart(2, "0")}`}
              </div>
              <div className="flex-1 min-w-0">
                <div className={`text-[10px] font-bold uppercase tracking-wider ${theme.textMuted}`}>
                  {restRemaining === 0 ? "Rest complete — ready to go" : "Resting"}
                </div>
                <div className={`text-[10px] ${theme.textMuted}`}>
                  Target: {restTotal}s · tap to adjust
                </div>
              </div>
              {/* Adjust buttons */}
              <div className="flex items-center gap-1 flex-shrink-0">
                <button onClick={() => setRestTotal(Math.max(15, restTotal - 15))}
                  className={`w-8 h-8 rounded-lg ${theme.surface} ${theme.surfaceText} font-bold text-xs`}>−15</button>
                <button onClick={() => setRestTotal(restTotal + 15)}
                  className={`w-8 h-8 rounded-lg ${theme.surface} ${theme.surfaceText} font-bold text-xs`}>+15</button>
                <button onClick={() => setRestRemaining(null)}
                  className="w-8 h-8 rounded-lg font-bold text-sm flex items-center justify-center"
                  style={{ color: theme.bg.includes("950") ? "#94a3b8" : "#64748b" }}>×</button>
              </div>
            </div>
          </div>
        )}

        {/* Active set logger — when in superset mode, switches between A and B based on activeSide */}
        {!allDone && (() => {
          // Pick the right side's state
          const isB = isSupersetMode && activeSide === "B";
          const sideSet = isB ? bCurrentSet : currentSet;
          const setSide = isB ? setBCurrentSet : setCurrentSet;
          const sideSets = isB ? bSets : sets;
          const sideTotal = isB ? bTotalSets : totalSets;
          const sideRange = isB ? bRepRange : repRange;
          const sideIsTimed = isB ? bIsTimed : isTimed;
          const sideIsBodyweight = isB ? bIsBodyweight : isBodyweight;
          const sideLastSession = isB ? bLastSession : lastSession;
          const sideName = isB ? supersetPartner.name : (swappedTo || exercise.name);
          const sideReps = isB ? supersetPartner.reps : exercise.reps;

          return (
          <div className="px-4 mt-4">
            <div className={`${theme.card} rounded-2xl border-2 p-5`} style={{ borderColor: ORANGE }}>
              {isSupersetMode && (
                <div className="flex items-center justify-between mb-3 -mt-1">
                  <div className="flex items-center gap-1.5">
                    <span className="text-[9px] font-bold uppercase tracking-wider px-1.5 py-0.5 rounded" style={{ backgroundColor: ORANGE, color: "white" }}>
                      {activeSide}
                    </span>
                    <span className={`text-xs font-semibold ${theme.text} truncate`}>{sideName}</span>
                  </div>
                  <div className={`text-[10px] ${theme.textMuted}`}>
                    {nextSide(isB ? sets.length : sets.length + (isB ? 0 : 1), isB ? bSets.length + 1 : bSets.length) === "A" && !isB
                      ? "then →" : nextSide(sets.length + (isB ? 0 : 1), bSets.length + (isB ? 1 : 0)) === "B" ? "then →" : ""}
                  </div>
                </div>
              )}
              <div className="flex items-center justify-between mb-3">
                <h3 className={`font-bold ${theme.text}`}>Set {sideSets.length + 1} of {sideTotal}</h3>
                {sideLastSession[sideSets.length] && (
                  <div className={`text-[10px] ${theme.textMuted}`}>
                    last: {sideIsTimed ? `${sideLastSession[sideSets.length].seconds}s`
                      : sideIsBodyweight ? `${sideLastSession[sideSets.length].reps} reps`
                      : `${sideLastSession[sideSets.length].weight}kg × ${sideLastSession[sideSets.length].reps}`}
                  </div>
                )}
              </div>

              {/* Timed exercise: stopwatch */}
              {sideIsTimed && (
                <TimerInput
                  value={sideSet.seconds}
                  setValue={v => setSide({ ...sideSet, seconds: v })}
                  target={sideLastSession[sideSets.length]?.seconds || 30}
                  theme={theme} />
              )}

              {/* Bodyweight: just reps */}
              {!sideIsTimed && sideIsBodyweight && (
                <div className="mb-3">
                  <label className={`block text-xs ${theme.textSubtle} mb-1`}>Reps</label>
                  <NumInput value={sideSet.reps} setValue={v => setSide({ ...sideSet, reps: v })} suffix="reps" step={1} theme={theme} />
                  <p className={`text-[10px] ${theme.textMuted} mt-1`}>Target range: {sideReps}</p>
                </div>
              )}

              {/* Weighted: weight + reps */}
              {!sideIsTimed && !sideIsBodyweight && (
                <>
                  <div className="mb-3">
                    <label className={`block text-xs ${theme.textSubtle} mb-1`}>Weight (kg)</label>
                    <NumInput value={sideSet.weight} setValue={v => setSide({ ...sideSet, weight: v })} suffix="kg" step={2.5} theme={theme} />
                  </div>
                  <div className="mb-3">
                    <label className={`block text-xs ${theme.textSubtle} mb-1`}>Reps</label>
                    <NumInput value={sideSet.reps} setValue={v => setSide({ ...sideSet, reps: v })} suffix="reps" step={1} theme={theme} />
                    <p className={`text-[10px] ${theme.textMuted} mt-1`}>Target range: {sideReps}</p>
                  </div>
                </>
              )}

              {/* RIR — for all modes */}
              <div className="mb-3">
                <label className={`block text-xs ${theme.textSubtle} mb-1`}>Reps in reserve (RIR)</label>
                <div className="grid grid-cols-4 gap-1.5">
                  {[
                    { v: 0, l: "0", sub: "failure" },
                    { v: 1, l: "1", sub: "1 left" },
                    { v: 2, l: "2", sub: "2 left" },
                    { v: 3, l: "2+", sub: "loads left" },
                  ].map(o => (
                    <button key={o.v} onClick={() => setSide({ ...sideSet, rir: o.v })}
                      className="h-12 rounded-lg font-bold text-sm"
                      style={{ backgroundColor: sideSet.rir === o.v ? NAVY : "", color: sideSet.rir === o.v ? "white" : "" }}>
                      <div className={sideSet.rir === o.v ? "flex flex-col items-center justify-center h-full" : `${theme.surface} ${theme.surfaceText} h-full flex flex-col items-center justify-center rounded-lg`}>
                        <div>{o.l}</div>
                        <div className="text-[8px] font-normal opacity-70">{o.sub}</div>
                      </div>
                    </button>
                  ))}
                </div>
              </div>

              <button onClick={logSet}
                disabled={sideIsTimed ? sideSet.seconds === 0 : sideIsBodyweight ? sideSet.reps === 0 : (sideSet.weight === 0 || sideSet.reps === 0)}
                className="w-full h-14 text-white rounded-xl font-bold text-base disabled:opacity-40"
                style={{ backgroundColor: ORANGE }}>
                {isSupersetMode
                  ? `Log ${activeSide}${sideSets.length + 1} → ${nextSide(isB ? sets.length : sets.length + 1, isB ? bSets.length + 1 : bSets.length) === null ? "finish" : nextSide(isB ? sets.length : sets.length + 1, isB ? bSets.length + 1 : bSets.length) === "A" ? `then A${sets.length + 1}` : `then B${bSets.length + 1}`}`
                  : `Log set ${sideSets.length + 1} →`}
              </button>
            </div>
          </div>
          );
        })()}

        {/* Finish button shows when all sets done */}
        {allDone && !showCelebration && (
          <div className="px-4 mt-4">
            {(() => {
              const volumeDiff = currentVolume - lastVolume;
              const volumeGap = lastVolume - currentVolume; // positive = need more
              // Calc what would beat last week with same weight as final set
              const finalSet = sets[sets.length - 1];
              const repsNeededSameWeight = finalSet.weight > 0 ? Math.ceil(volumeGap / finalSet.weight) + 1 : 0;
              const lowerWeight = Math.max(2.5, finalSet.weight - 5);
              const repsNeededLowerWeight = lowerWeight > 0 ? Math.ceil(volumeGap / lowerWeight) + 1 : 0;

              if (beatLastWeek || lastVolume === 0) {
                // BEAT last week — celebrate, just finish
                return (
                  <div className={`${theme.card} rounded-2xl border-2 p-5 text-center`} style={{ borderColor: "#10b981", backgroundColor: "#f0fdf4" }}>
                    <div className="text-4xl mb-2">🏆</div>
                    <h3 className="font-bold text-emerald-900 mb-1">All sets complete</h3>
                    <p className="text-sm text-emerald-700 mb-3">
                      {lastVolume === 0
                        ? `${Math.round(currentVolume).toLocaleString()} kg banked — baseline set!`
                        : `Beat last week by ${Math.round(volumeDiff).toLocaleString()} kg`}
                    </p>
                    <button onClick={() => finishWithCelebration(sets, true)} className="w-full h-12 rounded-xl font-bold text-white" style={{ backgroundColor: "#10b981" }}>
                      Finish exercise →
                    </button>
                  </div>
                );
              }

              if (Math.abs(volumeDiff) < lastVolume * 0.02) {
                // MATCHED last week (within 2%) — give them the choice
                return (
                  <div className={`${theme.card} rounded-2xl border-2 p-5`} style={{ borderColor: ORANGE, backgroundColor: `${ORANGE}10` }}>
                    <div className="text-center mb-3">
                      <div className="mb-2 flex justify-center"><BrandIcon name="weight" size={28} color={ORANGE} strokeWidth={1.6} /></div>
                      <h3 className="font-bold text-base" style={{ color: "#92400e" }}>You matched last week</h3>
                      <p className="text-xs mt-1" style={{ color: "#92400e" }}>{Math.round(currentVolume).toLocaleString()} vs {Math.round(lastVolume).toLocaleString()} kg. One more set to overload?</p>
                    </div>
                    <div className="space-y-2">
                      {finalSet.weight > 0 && (
                        <button onClick={() => addPushSet({ weight: finalSet.weight, reps: repsNeededSameWeight })}
                          className="w-full p-3 rounded-xl text-white font-semibold text-sm" style={{ backgroundColor: ORANGE }}>
                          Push: {finalSet.weight}kg × {repsNeededSameWeight} reps
                          <div className="text-[10px] font-normal opacity-90 mt-0.5">Same weight, beats last week by {Math.round(finalSet.weight * repsNeededSameWeight - volumeGap)}kg</div>
                        </button>
                      )}
                      <button onClick={() => finishWithCelebration(sets, false)} className={`w-full h-11 ${theme.surface} ${theme.surfaceText} rounded-xl font-semibold text-sm`}>
                        Finish here ({Math.round(currentVolume).toLocaleString()}kg)
                      </button>
                    </div>
                  </div>
                );
              }

              // BELOW last week — motivation + 2 options + finish
              return (
                <div className={`${theme.card} rounded-2xl border-2 p-5`} style={{ borderColor: ORANGE, backgroundColor: `${ORANGE}10` }}>
                  <div className="text-center mb-3">
                    <div className="mb-2 flex justify-center"><BrandIcon name="target" size={28} color={ORANGE} strokeWidth={1.6} /></div>
                    <h3 className="font-bold text-base" style={{ color: "#92400e" }}>{Math.round(volumeGap).toLocaleString()}kg short of last week</h3>
                    <p className="text-xs mt-1" style={{ color: "#92400e" }}>You can still beat it. Add one more set?</p>
                  </div>
                  <div className="space-y-2">
                    {finalSet.weight > 0 && repsNeededSameWeight <= 30 && (
                      <button onClick={() => addPushSet({ weight: finalSet.weight, reps: repsNeededSameWeight })}
                        className="w-full p-3 rounded-xl text-left text-white font-semibold text-sm" style={{ backgroundColor: ORANGE }}>
                        Same weight push
                        <div className="text-[11px] font-normal opacity-90 mt-0.5">{finalSet.weight}kg × {repsNeededSameWeight} reps · gives you the win</div>
                      </button>
                    )}
                    {lowerWeight > 0 && lowerWeight < finalSet.weight && repsNeededLowerWeight <= 30 && (
                      <button onClick={() => addPushSet({ weight: lowerWeight, reps: repsNeededLowerWeight })}
                        className="w-full p-3 rounded-xl text-left text-white font-semibold text-sm" style={{ backgroundColor: NAVY }}>
                        🔻 Back-off set (drop weight)
                        <div className="text-[11px] font-normal opacity-90 mt-0.5">{lowerWeight}kg × {repsNeededLowerWeight} reps · easier to overload, still progresses</div>
                      </button>
                    )}
                    <button onClick={() => finishWithCelebration(sets, false)} className={`w-full h-11 ${theme.surface} ${theme.surfaceText} rounded-xl font-semibold text-sm`}>
                      Finish here ({Math.round(currentVolume).toLocaleString()}kg)
                    </button>
                  </div>
                </div>
              );
            })()}
          </div>
        )}
      </div>

      {/* Celebration / motivation overlay */}
      {showCelebration && (() => {
        const { tone, headline, sub } = showCelebration;
        const bg = tone === "win" || tone === "first" ? "#10b981"
                 : tone === "match" ? ORANGE
                 : NAVY;
        const accent = tone === "win" || tone === "first" ? "#10b981"
                     : tone === "match" ? ORANGE
                     : NAVY;
        return (
          <div className="fixed inset-0 z-50 flex items-center justify-center px-5" style={{ backgroundColor: "rgba(0,0,0,0.7)" }} onClick={dismissCelebration}>
            <div className="rounded-2xl p-6 max-w-sm w-full text-center shadow-2xl" style={{ background: `linear-gradient(135deg, ${bg}, ${tone === "miss" ? "#0f172a" : `${accent}dd`})` }} onClick={e => e.stopPropagation()}>
              <h2 className="text-3xl font-bold text-white mb-3">{headline}</h2>
              <p className="text-white/90 text-sm leading-relaxed mb-6">{sub}</p>
              {tone === "win" && (
                <div className="flex justify-center gap-2 mb-6 text-2xl">
                  <span className="animate-bounce" style={{ animationDelay: "0s" }}>🎉</span>
                  <span className="animate-bounce" style={{ animationDelay: "0.1s" }}>💪</span>
                  <span className="animate-bounce" style={{ animationDelay: "0.2s" }}>🔥</span>
                </div>
              )}
              <button onClick={dismissCelebration} className="w-full h-12 rounded-xl font-bold text-base bg-white" style={{ color: accent }}>
                Continue →
              </button>
            </div>
          </div>
        );
      })()}

      {/* Swap modal */}
      {showSwap && (
        <SwapModal exercise={exercise} theme={theme}
          onClose={() => setShowSwap(false)}
          onResult={(reason, replacement) => {
            setSwapResult({ reason, replacement });
            if (replacement) setSwappedTo(replacement);
            setShowSwap(false);
          }} />
      )}

      {/* How-to modal */}
      {/* Calibration modal — first time using exercise */}
      {showCalibration && (
        <CalibrationModal exercise={exercise} profile={profile} theme={theme}
          onClose={() => setShowCalibration(false)}
          onConfirm={(weight) => {
            setCurrentSet({ weight, reps: repRange.top, rir: 0, seconds: 0 });
            setShowCalibration(false);
          }} />
      )}

      {showHowTo && (() => {
        const exData = EXERCISE_LIBRARY[exercise.name] || { muscle: "Legs", equipment: "" };
        const cues = FORM_CUES[exercise.name] || DEFAULT_CUES;
        return (
          <Modal title={exercise.name} onClose={() => setShowHowTo(false)} theme={theme}>
            <div className="grid grid-cols-2 gap-3 mb-4">
              <div className={`${theme.surface} rounded-xl p-3 flex items-center justify-center`}>
                <div className="w-full" style={{ maxWidth: "120px" }}>
                  <MuscleDiagram muscle={exData.muscle} theme={theme} />
                </div>
              </div>
              <div className="flex flex-col justify-center">
                <div className={`text-[10px] font-bold uppercase tracking-wide ${theme.textMuted}`}>Targets</div>
                <div className={`text-base font-bold ${theme.text} mt-0.5`}>{exData.muscle}</div>
                <div className={`text-[10px] font-bold uppercase tracking-wide ${theme.textMuted} mt-3`}>Equipment</div>
                <div className={`text-sm font-semibold ${theme.text} mt-0.5`}>{exData.equipment || "—"}</div>
                <div className={`text-[10px] font-bold uppercase tracking-wide ${theme.textMuted} mt-3`}>Today's plan</div>
                <div className="text-sm font-semibold mt-0.5" style={{ color: ORANGE }}>{exercise.sets} × {exercise.reps}</div>
              </div>
            </div>

            <div className="rounded-xl p-3 mb-3" style={{ backgroundColor: `${NAVY}08`, border: `1px solid ${NAVY}22` }}>
              <div className="text-[10px] font-bold uppercase tracking-wide mb-2" style={{ color: NAVY }}>① Set up</div>
              <ul className="space-y-1.5">
                {cues.setup.map((c, i) => <li key={i} className={`text-xs flex items-start gap-2 ${theme.text}`}><span className="font-bold flex-shrink-0" style={{ color: NAVY }}>•</span><span>{c}</span></li>)}
              </ul>
            </div>

            <div className="rounded-xl p-3 mb-3" style={{ backgroundColor: `${ORANGE}10`, border: `1px solid ${ORANGE}33` }}>
              <div className="text-[10px] font-bold uppercase tracking-wide mb-2" style={{ color: ORANGE }}>② Execution</div>
              <ul className="space-y-1.5">
                {cues.execution.map((c, i) => <li key={i} className={`text-xs flex items-start gap-2 ${theme.text}`}><span className="font-bold flex-shrink-0" style={{ color: ORANGE }}>→</span><span>{c}</span></li>)}
              </ul>
            </div>

            <div className="rounded-xl p-3 mb-4" style={{ backgroundColor: "#fef2f2", border: "1px solid #fecaca" }}>
              <div className="text-[10px] font-bold uppercase tracking-wide mb-2" style={{ color: "#b91c1c" }}>③ Common mistakes</div>
              <ul className="space-y-1.5">
                {cues.mistakes.map((c, i) => <li key={i} className="text-xs flex items-start gap-2" style={{ color: "#7f1d1d" }}><span className="font-bold flex-shrink-0">✗</span><span>{c}</span></li>)}
              </ul>
            </div>

            <button onClick={() => setShowHowTo(false)} className="w-full h-12 text-white rounded-xl font-semibold" style={{ backgroundColor: ORANGE }}>Got it</button>
          </Modal>
        );
      })()}

      {/* Notes modal */}
      {showNotes && (() => {
        const isPT = session.role === "PT";
        return (
          <Modal title="Notes" onClose={() => setShowNotes(false)} theme={theme}>
            <p className={`text-xs ${theme.textMuted} mb-3`}>Notes appear at the top every time you do this exercise.</p>
            <TextArea label="My notes" value={userNote} setValue={setUserNote} placeholder="e.g. Use medium grip. Keep elbows tucked." rows={3} theme={theme} />
            {isPT ? (
              <TextArea label="PT notes (visible to client)" value={ptNote} setValue={setPtNote} placeholder="Coaching notes for your client..." rows={3} theme={theme} />
            ) : (
              <div className="mb-4">
                <label className={`block text-sm font-medium ${theme.textSubtle} mb-1.5`}>PT notes</label>
                {ptNote ? (
                  <div className="rounded-lg p-3 border" style={{ backgroundColor: "#f5f3ff", borderColor: "#ddd6fe" }}>
                    <div className="text-sm" style={{ color: "#5b21b6" }}>{ptNote}</div>
                  </div>
                ) : (
                  <div className={`rounded-lg p-3 ${theme.surface} text-xs ${theme.textMuted} italic`}>
                    No PT notes yet. Your trainer can add notes from their app.
                  </div>
                )}
              </div>
            )}
            <button onClick={saveNotes} className="w-full h-12 text-white rounded-xl font-semibold" style={{ backgroundColor: ORANGE }}>Save</button>
          </Modal>
        );
      })()}

      {/* Swap confirmation banner */}
      {swapResult && !showSwap && (
        <div className="fixed bottom-4 left-4 right-4 max-w-md mx-auto">
          <div className={`${theme.card} rounded-xl border-2 p-3 shadow-lg`} style={{ borderColor: ORANGE }}>
            <div className="text-xs font-bold uppercase tracking-wide mb-1" style={{ color: ORANGE }}>
              {swapResult.reason === "occupied" ? "🟡 Stays in plan" : swapResult.reason === "missing" ? "🔴 Removed for future weeks" : "🟠 One-off swap"}
            </div>
            <p className={`text-xs ${theme.textMuted}`}>
              {swapResult.reason === "occupied" && `Someone else is using it. ${exercise.name} stays in next week's plan.`}
              {swapResult.reason === "missing" && `${exercise.name} flagged as unavailable. Will be replaced in future weeks.`}
              {swapResult.reason === "other" && `Doing ${swapResult.replacement} today only.`}
            </p>
            <p className={`text-[10px] ${theme.textMuted} mt-1 italic`}>Multi-week plan persistence coming in next update.</p>
          </div>
        </div>
      )}

      {/* First-time superset alternation explainer */}
      {showSupersetIntro && (
        <Modal title="Superset round" onClose={async () => {
          await storage.set(userKey(session.id, "superset-intro-seen"), true);
          setShowSupersetIntro(false);
        }} theme={theme}>
          <p className={`text-sm ${theme.text} mb-3 leading-relaxed`}>
            This exercise is paired with <strong>{supersetPartner.name}</strong>. The app alternates between the two:
          </p>
          <div className="space-y-2 mb-4">
            <div className={`${theme.surface} rounded-lg p-3 flex items-center gap-3`}>
              <div className="w-8 h-8 rounded-full flex items-center justify-center font-bold text-white text-xs" style={{ backgroundColor: ORANGE }}>1</div>
              <div className={`text-xs ${theme.text}`}>Do A set 1 (the exercise you opened)</div>
            </div>
            <div className={`${theme.surface} rounded-lg p-3 flex items-center gap-3`}>
              <div className="w-8 h-8 rounded-full flex items-center justify-center font-bold text-white text-xs" style={{ backgroundColor: ORANGE }}>2</div>
              <div className={`text-xs ${theme.text}`}>Go straight to B set 1 (the partner) — no rest between</div>
            </div>
            <div className={`${theme.surface} rounded-lg p-3 flex items-center gap-3`}>
              <div className="w-8 h-8 rounded-full flex items-center justify-center font-bold text-white text-xs" style={{ backgroundColor: ORANGE }}>3</div>
              <div className={`text-xs ${theme.text}`}>Rest 60s. Then A set 2 → B set 2 → rest. Repeat.</div>
            </div>
          </div>
          <p className={`text-[11px] ${theme.textMuted} mb-3 leading-snug`}>
            The active logger card switches automatically after each set. Both forecasts stay visible above so you can see what's next. Rest timer kicks in only between rounds, not between A and B.
          </p>
          <p className={`text-[11px] ${theme.textMuted} mb-4 italic`}>
            Don't like supersets? Back out → tap "Split out" on the pair → run them as straight sets.
          </p>
          <button onClick={async () => {
            await storage.set(userKey(session.id, "superset-intro-seen"), true);
            setShowSupersetIntro(false);
          }} className="w-full h-12 text-white rounded-xl font-semibold" style={{ backgroundColor: ORANGE }}>
            Got it
          </button>
        </Modal>
      )}

      {/* Rep range editor — lets user override the plan's prescribed rep range for this exercise */}
      {showRepRangeEditor && (
        <RepRangeEditor
          exercise={exercise}
          session={session}
          theme={theme}
          onClose={() => setShowRepRangeEditor(false)}
          onSave={async (newRange) => {
            const prefs = (await storage.get(userKey(session.id, "exercise-prefs"))) || {};
            const overrides = { ...(prefs.repRangeOverrides || {}) };
            if (newRange === null || newRange === "") {
              delete overrides[exercise.name];
            } else {
              overrides[exercise.name] = newRange;
            }
            await storage.set(userKey(session.id, "exercise-prefs"), {
              ...prefs,
              repRangeOverrides: overrides,
            });
            setShowRepRangeEditor(false);
            // Trigger reload by calling onComplete-style behavior — but only for the override.
            // Easiest: just close. Logger will use the new range next session.
          }} />
      )}

      {/* Dropset editor */}
      {dropsetFor && (
        <Modal title={`Dropset on Set ${dropsetFor.setIndex + 1}`} onClose={() => setDropsetFor(null)} theme={theme}>
          <p className={`text-xs ${theme.textMuted} mb-3 leading-snug`}>
            After your working set, immediately drop the weight and rep out. Add 1-3 drops below. Common patterns: drop ~20% for one rep-out set, or do triple-drops at ~70/50/30% of working weight.
          </p>
          {dropsetFor.draftDrops.map((d, di) => (
            <div key={di} className={`${theme.surface} rounded-lg p-3 mb-2`}>
              <div className="flex items-center justify-between mb-2">
                <span className={`text-xs font-bold uppercase tracking-wide ${theme.text}`}>Drop {di + 1}</span>
                {dropsetFor.draftDrops.length > 1 && (
                  <button onClick={() => setDropsetFor({
                    ...dropsetFor,
                    draftDrops: dropsetFor.draftDrops.filter((_, i) => i !== di),
                  })} className="text-[10px] underline" style={{ color: "#ef4444" }}>Remove</button>
                )}
              </div>
              <div className="grid grid-cols-2 gap-2">
                <div>
                  <label className={`text-[10px] font-bold ${theme.textMuted}`}>Weight (kg)</label>
                  <input type="number" inputMode="decimal" value={d.weight}
                    onChange={e => setDropsetFor({
                      ...dropsetFor,
                      draftDrops: dropsetFor.draftDrops.map((x, i) => i === di ? { ...x, weight: Number(e.target.value) || 0 } : x),
                    })}
                    step={2.5}
                    className={`w-full h-10 px-3 text-sm border-2 ${theme.border} ${theme.inputBg} ${theme.text} rounded-lg`} />
                </div>
                <div>
                  <label className={`text-[10px] font-bold ${theme.textMuted}`}>Reps</label>
                  <input type="number" inputMode="numeric" value={d.reps}
                    onChange={e => setDropsetFor({
                      ...dropsetFor,
                      draftDrops: dropsetFor.draftDrops.map((x, i) => i === di ? { ...x, reps: Number(e.target.value) || 0 } : x),
                    })}
                    className={`w-full h-10 px-3 text-sm border-2 ${theme.border} ${theme.inputBg} ${theme.text} rounded-lg`} />
                </div>
              </div>
            </div>
          ))}
          {dropsetFor.draftDrops.length < 3 && (
            <button onClick={() => {
              // Seed next drop at ~70% of last drop's weight
              const last = dropsetFor.draftDrops[dropsetFor.draftDrops.length - 1];
              const nextWeight = Math.max(2.5, Math.round((last.weight * 0.7) / 2.5) * 2.5);
              setDropsetFor({
                ...dropsetFor,
                draftDrops: [...dropsetFor.draftDrops, { weight: nextWeight, reps: Math.max(1, last.reps - 1) }],
              });
            }} className={`w-full h-10 rounded-lg text-xs font-semibold border-2 mb-3`}
              style={{ color: "#15803d", borderColor: "#15803d55" }}>
              + Add another drop
            </button>
          )}
          <div className="flex gap-2">
            {sets[dropsetFor.setIndex]?.drops?.length > 0 && (
              <button onClick={() => {
                // Remove drops entirely
                const newSets = sets.map((x, i) => i === dropsetFor.setIndex ? { ...x, drops: undefined } : x);
                setSets(newSets);
                setDropsetFor(null);
              }} className="h-12 px-4 rounded-xl font-semibold text-sm" style={{ color: "#ef4444", backgroundColor: "#ef444415" }}>
                Clear
              </button>
            )}
            <button onClick={() => setDropsetFor(null)} className={`flex-1 h-12 ${theme.surface} ${theme.surfaceText} rounded-xl font-semibold`}>Cancel</button>
            <button onClick={() => {
              const validDrops = dropsetFor.draftDrops.filter(d => d.weight > 0 && d.reps > 0);
              const newSets = sets.map((x, i) => i === dropsetFor.setIndex ? { ...x, drops: validDrops.length > 0 ? validDrops : undefined } : x);
              setSets(newSets);
              setDropsetFor(null);
            }} disabled={!dropsetFor.draftDrops.some(d => d.weight > 0 && d.reps > 0)}
              className="flex-1 h-12 text-white rounded-xl font-semibold disabled:opacity-50"
              style={{ backgroundColor: ORANGE }}>Save</button>
          </div>
        </Modal>
      )}
    </div>
  );
}

// ============================================================
// REP RANGE EDITOR — override the plan's prescribed range per exercise
// ============================================================
function RepRangeEditor({ exercise, theme, onClose, onSave }) {
  const currentRange = parseRepRange(exercise.reps);
  const [bot, setBot] = useState(currentRange.bot);
  const [top, setTop] = useState(currentRange.top);
  // Quick presets: strength / hypertrophy / endurance
  const presets = [
    { l: "Strength", range: "4-6" },
    { l: "Hypertrophy", range: "8-12" },
    { l: "Endurance", range: "15-20" },
  ];
  return (
    <Modal title="Rep range" onClose={onClose} theme={theme}>
      <p className={`text-xs ${theme.textMuted} mb-3 leading-snug`}>
        Current: <span className={theme.text}>{exercise.reps}</span> reps.
        {exercise.repsOverridden && <span className="ml-1 italic">(overridden)</span>}
      </p>
      <p className={`text-[10px] ${theme.textMuted} mb-3`}>
        Pick a preset or set custom min/max. Override applies only to this exercise; other exercises keep their original ranges.
      </p>
      <div className="grid grid-cols-3 gap-2 mb-4">
        {presets.map(p => {
          const sel = `${bot}-${top}` === p.range;
          return (
            <button key={p.l} onClick={() => {
              const [b, t] = p.range.split("-").map(n => parseInt(n, 10));
              setBot(b); setTop(t);
            }}
              className="h-12 rounded-lg font-semibold text-xs"
              style={{ backgroundColor: sel ? ORANGE : "", color: sel ? "white" : "" }}>
              <div className={sel ? "" : `${theme.surface} ${theme.surfaceText} h-full flex flex-col items-center justify-center rounded-lg`}>
                <div>{p.l}</div>
                <div className="text-[9px] opacity-70">{p.range}</div>
              </div>
            </button>
          );
        })}
      </div>
      <div className="grid grid-cols-2 gap-2 mb-3">
        <div>
          <label className={`text-[10px] font-bold uppercase tracking-wider ${theme.textMuted}`}>Min reps</label>
          <NumInput value={bot} setValue={v => setBot(Math.max(1, v))} suffix="reps" step={1} theme={theme} />
        </div>
        <div>
          <label className={`text-[10px] font-bold uppercase tracking-wider ${theme.textMuted}`}>Max reps</label>
          <NumInput value={top} setValue={v => setTop(Math.max(bot, v))} suffix="reps" step={1} theme={theme} />
        </div>
      </div>
      {top < bot && (
        <p className={`text-[10px] mb-2`} style={{ color: "#ef4444" }}>Max must be ≥ min</p>
      )}
      <div className="flex gap-2">
        {exercise.repsOverridden && (
          <button onClick={() => onSave(null)}
            className="h-12 px-4 rounded-xl font-semibold text-sm"
            style={{ color: "#ef4444", backgroundColor: "#ef444415" }}>
            Reset
          </button>
        )}
        <button onClick={onClose} className={`flex-1 h-12 ${theme.surface} ${theme.surfaceText} rounded-xl font-semibold`}>Cancel</button>
        <button onClick={() => onSave(`${bot}-${top}`)} disabled={top < bot || bot < 1}
          className="flex-1 h-12 text-white rounded-xl font-semibold disabled:opacity-50"
          style={{ backgroundColor: ORANGE }}>Save</button>
      </div>
    </Modal>
  );
}

// ============================================================
// SWAP MODAL — three options
// ============================================================
function SwapModal({ exercise, theme, onClose, onResult }) {
  const [step, setStep] = useState("reason"); // reason | pick
  const [reason, setReason] = useState(null);

  const exData = EXERCISE_LIBRARY[exercise.name];
  const alts = exData?.alts || [];

  const pickReason = (r) => {
    setReason(r);
    if (alts.length > 0) setStep("pick");
    else onResult(r, null);
  };

  const pickAlt = (alt) => {
    onResult(reason, alt);
  };

  if (step === "reason") {
    return (
      <Modal title="Why is it unavailable?" onClose={onClose} theme={theme}>
        <p className={`text-xs ${theme.textMuted} mb-4`}>How we handle it depends on why.</p>
        <div className="space-y-2">
          <button onClick={() => pickReason("occupied")} className="w-full p-4 rounded-xl border-2 text-left active:opacity-80" style={{ borderColor: "#fde68a", backgroundColor: "#fffbeb" }}>
            <div className="text-2xl mb-1">🟡</div>
            <div className="font-bold text-amber-900">Someone's on it</div>
            <p className="text-xs text-amber-700 mt-1">Equipment is in this gym, just busy now. SINC will keep it in next week's plan.</p>
          </button>
          <button onClick={() => pickReason("missing")} className="w-full p-4 rounded-xl border-2 text-left active:opacity-80" style={{ borderColor: "#fecaca", backgroundColor: "#fef2f2" }}>
            <div className="text-2xl mb-1">🔴</div>
            <div className="font-bold text-red-900">Not in this gym</div>
            <p className="text-xs text-red-700 mt-1">This equipment isn't available here at all. Permanently swap it in future weeks.</p>
          </button>
          <button onClick={() => pickReason("other")} className="w-full p-4 rounded-xl border-2 text-left active:opacity-80" style={{ borderColor: `${ORANGE}55`, backgroundColor: `${ORANGE}10` }}>
            <div className="text-2xl mb-1">🟠</div>
            <div className="font-bold" style={{ color: ORANGE }}>Other reason</div>
            <p className="text-xs mt-1" style={{ color: "#92400e" }}>Just want to swap it once today (injury, mood, time-saving).</p>
          </button>
        </div>
      </Modal>
    );
  }

  return (
    <Modal title="Pick a replacement" onClose={onClose} theme={theme}>
      <p className={`text-xs ${theme.textMuted} mb-4`}>SINC suggests alternatives that hit the same muscle.</p>
      <div className="space-y-2">
        {alts.map(alt => {
          const altData = EXERCISE_LIBRARY[alt];
          return (
            <button key={alt} onClick={() => pickAlt(alt)} className={`w-full p-3 rounded-xl border-2 ${theme.border} text-left active:opacity-80 ${theme.card}`}>
              <div className={`font-bold ${theme.text}`}>{alt}</div>
              <div className={`text-xs ${theme.textMuted} mt-0.5`}>{altData?.muscle} · {altData?.equipment}</div>
            </button>
          );
        })}
      </div>
      <button onClick={() => setStep("reason")} className={`w-full h-11 ${theme.surface} ${theme.surfaceText} rounded-xl text-sm font-semibold mt-3`}>← Back</button>
    </Modal>
  );
}
